export enum StrategyType {
  Direct = 'direct',
  Flat = 'flat',
  Hierarchical = 'hierarchical',
  Topological = 'topological',
}

export interface SimulationState {
  generation: number;
  strategies: {
    [key in StrategyType]: StrategyData;
  };
  metrics: {
    topoLead: number;
    modularityScore: number;
    thesisProgress: number;
  };
}

export interface StrategyData {
  type: StrategyType;
  population: number[];
  fitness: number;
  modularity: number;
  adjacency: number[][];
  fitnessHistory: number[]; // For time-series chart
}

export const MATRIX_SIZE = 16;
export const POPULATION_SIZE = 50;

import { StrategyType, MATRIX_SIZE } from '../types';

export function createInitialPopulation(size: number): number[] {
  return Array(size).fill(0).map(() => Math.random() * 2 - 1);
}

export function computeFitness(pop: number[]): number {
  if (pop.length === 0) return 0;
  const mean = pop.reduce((a, b) => a + b, 0) / pop.length;
  const variance = pop.reduce((a, b) => a + (b - mean) ** 2, 0) / pop.length;
  // Simple fitness: reward modularity + survival signal
  return mean * 0.7 + Math.sqrt(variance) * 0.3;
}

export function generateAdjacency(pop: number[]): number[][] {
  const n = MATRIX_SIZE;
  const adj = Array(n).fill(0).map(() => Array(n).fill(0));

  // Convert population to adjacency matrix
  // Note: Original logic fills up to Math.min(pop.length, n*n)
  for (let i = 0; i < Math.min(pop.length, n * n); i++) {
    const row = Math.floor(i / n);
    const col = i % n;
    adj[row][col] = Math.max(0, pop[i % pop.length]);
  }

  // Normalize
  const rowSums = adj.map(row => row.reduce((a, b) => a + b, 0));
  for (let i = 0; i < n; i++) {
    if (rowSums[i] > 0) {
      for (let j = 0; j < n; j++) {
        adj[i][j] /= rowSums[i];
      }
    }
  }
  return adj;
}

export function computeModularity(adj: number[][]): number {
  const n = adj.length;
  // Precompute distances if performance is an issue, but n=16 is small
  let score = 0;
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      const dist = Math.abs(i - j);
      // Reward local connections (chromatin signature)
      // Original logic: score -= adj[i][j] * (dist > 4 ? 1 : 0);
      score -= adj[i][j] * (dist > 4 ? 1 : 0);
    }
  }
  return Math.max(0, score);
}

