import { useState, useEffect, useRef, useCallback } from 'react';
import { StrategyType, SimulationState, StrategyData, POPULATION_SIZE } from '../types';
import { createInitialPopulation, evolvePopulation, generateAdjacency, computeFitness, computeModularity } from '../utils/simulation';

const HISTORY_LENGTH = 50;

export const useExperiment = () => {
  const [simulationState, setSimulationState] = useState<SimulationState | null>(null);
  const stateRef = useRef<SimulationState | null>(null);
  const frameIdRef = useRef<number>(0);

  // Initialize
  useEffect(() => {
    const initialStrategies = Object.values(StrategyType).reduce((acc, type) => {
      const pop = createInitialPopulation(POPULATION_SIZE);
      const adj = generateAdjacency(pop);
      acc[type] = {
        type,
        population: pop,
        fitness: computeFitness(pop),
        modularity: computeModularity(adj),
        adjacency: adj,
        fitnessHistory: Array(HISTORY_LENGTH).fill(0)
      };
      return acc;
    }, {} as Record<StrategyType, StrategyData>);

    const initialState: SimulationState = {
      generation: 0,
      strategies: initialStrategies,
      metrics: {
        topoLead: 0,
        modularityScore: 0,
        thesisProgress: 0
      }
    };

    stateRef.current = initialState;
    setSimulationState(initialState);
  }, []);

  const tick = useCallback(() => {
    if (!stateRef.current) return;

    const currentStrategies = stateRef.current.strategies;
    const nextStrategies = {} as Record<StrategyType, StrategyData>;
    let topoFitness = 0;
    let maxOtherFitness = 0;
    let topoModularity = 0;

    // Evolve each strategy
    Object.values(StrategyType).forEach(type => {
      const prev = currentStrategies[type];
      const nextPop = evolvePopulation(prev.population, type);
      const nextFitness = computeFitness(nextPop);
      const nextAdj = generateAdjacency(nextPop);
      const nextModularity = computeModularity(nextAdj);

      const nextHistory = [...prev.fitnessHistory, nextFitness].slice(-HISTORY_LENGTH);

      nextStrategies[type] = {
        type,
        population: nextPop,
        fitness: nextFitness,
        modularity: nextModularity,
        adjacency: nextAdj,
        fitnessHistory: nextHistory
      };

      if (type === StrategyType.Topological) {
        topoFitness = nextFitness;
        topoModularity = nextModularity;
      } else {
        maxOtherFitness = Math.max(maxOtherFitness, nextFitness);
      }
    });

    const topoLead = topoFitness - maxOtherFitness;
    // Thesis progress calculation from snippet: (topoLead * 50 + modularityScore * 50)
    const thesisProgress = Math.min(100, Math.max(0, (topoLead * 50 + topoModularity * 50)));

    const nextState: SimulationState = {
      generation: stateRef.current.generation + 1,
      strategies: nextStrategies,
      metrics: {
        topoLead,
        modularityScore: topoModularity,
        thesisProgress
      }
    };

    stateRef.current = nextState;

    // Throttle UI updates slightly if needed, but for now 60fps is fine for this data size
    setSimulationState(nextState);

    frameIdRef.current = requestAnimationFrame(tick);
  }, []);

  useEffect(() => {
    frameIdRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameIdRef.current);
  }, [tick]);

  return simulationState;
};

import React, { useMemo } from 'react';
import { MATRIX_SIZE } from '../types';

interface HeatmapProps {
  adjacency: number[][];
  colorBase: [number, number, number]; // RGB tuple
}

const Heatmap: React.FC<HeatmapProps> = ({ adjacency, colorBase }) => {
  // Memoize the grid generation to avoid expensive recalcs if props strictly equal (though they change often)
  // Since adjacency changes every frame, memoization might not save much, but good practice.

  return (
    <div 
      className="grid gap-[1px] bg-slate-900 border border-slate-800 p-1"
      style={{ 
        gridTemplateColumns: `repeat(${MATRIX_SIZE}, 1fr)`,
        aspectRatio: '1/1'
      }}
    >
      {adjacency.map((row, r) => (
        row.map((val, c) => {
          const intensity = Math.min(1, Math.max(0, val));
          // Simple RGB interpolation from black/dark to Color
          const rVal = Math.floor(colorBase[0] * intensity);
          const gVal = Math.floor(colorBase[1] * intensity);
          const bVal = Math.floor(colorBase[2] * intensity);

          return (
            <div
              key={`${r}-${c}`}
              style={{
                backgroundColor: `rgb(${rVal}, ${gVal}, ${bVal})`,
              }}
              className="w-full h-full"
            />
          );
        })
      ))}
    </div>
  );
};

export default Heatmap;

import React from 'react';
import { ResponsiveContainer, LineChart, Line, YAxis } from 'recharts';

interface FitnessChartProps {
  data: number[];
  color: string;
}

const FitnessChart: React.FC<FitnessChartProps> = ({ data, color }) => {
  const chartData = data.map((val, i) => ({ i, val }));

  return (
    <div className="h-20 w-full mt-2">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData}>
          <YAxis domain={[-1, 1]} hide />
          <Line 
            type="monotone" 
            dataKey="val" 
            stroke={color} 
            strokeWidth={2} 
            dot={false}
            isAnimationActive={false} // Disable animation for real-time performance
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default FitnessChart;

