import { StrategyType, MATRIX_SIZE } from '../types';

export function createInitialPopulation(size: number): number[] {
  // We utilize a 1:1 mapping between population genes and matrix cells (16x16=256)
  // to ensure spatial strategies function correctly without aliasing.
  return Array(size).fill(0).map(() => Math.random() * 2 - 1);
}

export function computeFitness(pop: number[]): number {
  if (pop.length === 0) return 0;
  const mean = pop.reduce((a, b) => a + b, 0) / pop.length;
  const variance = pop.reduce((a, b) => a + (b - mean) ** 2, 0) / pop.length;
  // Adjusted fitness: Reward high variance (information) and positive signal
  return (mean * 0.5 + Math.sqrt(variance) * 0.5);
}

export function generateAdjacency(pop: number[]): number[][] {
  const n = MATRIX_SIZE;
  const adj = Array(n).fill(0).map(() => Array(n).fill(0));

  for (let i = 0; i < n * n; i++) {
    const row = Math.floor(i / n);
    const col = i % n;
    // Use modulo if population < n*n, though we aim for 1:1
    const geneVal = pop[i % pop.length];
    adj[row][col] = Math.max(0, geneVal);
  }

  // Normalize row sums to make it look like probability/interaction matrix
  // But keep relative intensity for visual impact
  const rowSums = adj.map(row => row.reduce((a, b) => a + b, 0));
  for (let i = 0; i < n; i++) {
    if (rowSums[i] > 0.001) {
      for (let j = 0; j < n; j++) {
        // Soft normalization to preserve some absolute intensity diffs
        adj[i][j] = adj[i][j] / (rowSums[i] * 0.8 + 0.2); 
      }
    }
  }
  return adj;
}

export function computeModularity(adj: number[][]): number {
  const n = adj.length;
  let score = 0;
  let totalWeight = 0;

  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      const weight = adj[i][j];
      totalWeight += weight;

      const dist = Math.abs(i - j);
      // Reward connections close to diagonal (TADs)
      // Penalize long range
      if (dist <= 3) {
        score += weight * (4 - dist); // High reward for very close
      } else {
        score -= weight * (dist * 0.5); // Penalty scales with distance
      }
    }
  }

  return totalWeight > 0 ? Math.max(0, score / totalWeight) : 0;
}

export function evolvePopulation(pop: number[], strategy: StrategyType): number[] {
  const nextPop = [...pop];
  const n = MATRIX_SIZE;

  for (let i = 0; i < nextPop.length; i++) {
    let gene = nextPop[i];

    // Basic thermal noise
    // Increased noise for all strategies to create more fluctuation
    gene += (Math.random() - 0.5) * 0.2;

    // Derived spatial coordinates (assuming row-major filling)
    const row = Math.floor(i / n);
    const col = i % n;
    const dist = Math.abs(row - col);

    if (strategy === StrategyType.Topological) {
      // Topological: Enforce diagonal dominance (TAD-like structures)
      if (dist < 3) {
        gene += 0.04; // Slightly reduced growth pressure
      } else {
        gene *= 0.92; // Slightly reduced decay pressure (harder to clear noise)
      }

      // Periodically boost random diagonal blocks to simulate TAD formation
      if (Math.random() < 0.01 && dist < 4) {
         gene += 0.5;
      }

    } else if (strategy === StrategyType.Hierarchical) {
       // Hierarchical: Quantize into discrete levels
       const levels = 4;
       const target = Math.round(gene * levels) / levels;
       gene = gene + (target - gene) * 0.15; // Stronger pull to structure

    } else if (strategy === StrategyType.Flat) {
       // Flat: Strong reversion to mean
       gene = gene * 0.9 + (Math.random() - 0.5) * 0.05;
       gene = Math.max(-0.2, Math.min(0.2, gene));
    } else {
       // Direct: Unconstrained
       // Occasional bursts of signal to compete
       if (Math.random() < 0.005) gene = 1;
    }

    // Hard Bounds
    nextPop[i] = Math.max(-1, Math.min(1, gene));
  }

  return nextPop;
}

import React, { useRef, useMemo, useLayoutEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment } from '@react-three/drei';
import * as THREE from 'three';
import { MATRIX_SIZE } from '../types';

interface Matrix3DProps {
  adjacency: number[][];
  colorBase: [number, number, number];
}

const InstancedBars: React.FC<{ adjacency: number[][]; colorBase: [number, number, number] }> = ({ adjacency, colorBase }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempObject = useMemo(() => new THREE.Object3D(), []);
  const tempColor = useMemo(() => new THREE.Color(), []);

  useLayoutEffect(() => {
    if (!meshRef.current) return;

    let idx = 0;
    const offset = MATRIX_SIZE / 2 - 0.5;

    for (let i = 0; i < MATRIX_SIZE; i++) {
      for (let j = 0; j < MATRIX_SIZE; j++) {
        const value = Math.max(0.01, adjacency[i][j]); // Ensure minimal height

        // Position: X and Z form the grid, Y is height
        tempObject.position.set(i - offset, value * 2, j - offset);
        tempObject.scale.set(0.8, value * 4, 0.8);
        tempObject.updateMatrix();

        meshRef.current.setMatrixAt(idx, tempObject.matrix);

        // Color based on intensity
        const intensity = Math.min(1, value);
        tempColor.setRGB(
            (colorBase[0]/255) * intensity, 
            (colorBase[1]/255) * intensity, 
            (colorBase[2]/255) * intensity
        );
        // Boost brightness for visibility
        if (value > 0.5) tempColor.multiplyScalar(1.5);

        meshRef.current.setColorAt(idx, tempColor);

        idx++;
      }
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;

  }, [adjacency, colorBase, tempObject, tempColor]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MATRIX_SIZE * MATRIX_SIZE]}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial 
        roughness={0.2} 
        metalness={0.8}
        emissive={new THREE.Color(colorBase[0]/255, colorBase[1]/255, colorBase[2]/255)}
        emissiveIntensity={0.2}
      />
    </instancedMesh>
  );
};

const Matrix3D: React.FC<Matrix3DProps> = ({ adjacency, colorBase }) => {
  return (
    <div className="w-full h-full min-h-[300px] relative bg-slate-900 rounded-lg overflow-hidden cursor-move">
      <Canvas>
        <PerspectiveCamera makeDefault position={[20, 20, 20]} fov={50} />
        <OrbitControls 
            enablePan={false} 
            minPolarAngle={0} 
            maxPolarAngle={Math.PI / 2.2} 
            autoRotate 
            autoRotateSpeed={1.0}
        />

        <ambientLight intensity={0.5} />
        <pointLight position={[10, 20, 10]} intensity={1.5} color="#ffffff" />
        <pointLight position={[-10, 5, -10]} intensity={1} color={new THREE.Color(colorBase[0]/255, colorBase[1]/255, colorBase[2]/255)} />

        <group position={[0, -2, 0]}>
            <InstancedBars adjacency={adjacency} colorBase={colorBase} />
            {/* Grid base */}
            <gridHelper args={[MATRIX_SIZE + 2, MATRIX_SIZE + 2, 0x334155, 0x1e293b]} position={[0, 0, 0]} />
        </group>

        <Environment preset="city" />
      </Canvas>
      <div className="absolute bottom-2 right-2 text-[10px] text-slate-500 font-mono bg-slate-950/50 px-2 py-1 rounded pointer-events-none border border-slate-800">
        RMB: ROTATE | WHEEL: ZOOM
      </div>
    </div>
  );
};

export default Matrix3D;

