import React, { useRef, useEffect } from 'react';
import { MATRIX_SIZE } from '../types';

interface HeatmapProps {
  adjacency: number[][];
  colorBase: [number, number, number]; // RGB tuple
}

const Heatmap: React.FC<HeatmapProps> = ({ adjacency, colorBase }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear background with deep dark slate (slate-950)
    ctx.fillStyle = '#020617'; 
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const cellSize = canvas.width / MATRIX_SIZE;
    const gap = 1;

    // Helper for linear interpolation
    const lerp = (start: number, end: number, t: number) => start + (end - start) * t;

    adjacency.forEach((row, r) => {
      row.forEach((val, c) => {
        // Clamp raw value
        const rawIntensity = Math.min(1, Math.max(0, val));

        // Perceptual scaling (Gamma correction)
        // Lifting low values to make them visible against the dark background
        const intensity = Math.pow(rawIntensity, 0.45); 

        // Dynamic Gradient Generation
        // We create a gradient from Dark Background -> ColorBase -> Bright/White
        // This mimics "fire" or "plasma" intensity ramps but keeps the strategy hue.

        let red, green, blue;

        // Background color reference (slate-950)
        const bgR = 2, bgG = 6, bgB = 23;

        // Threshold where we reach the pure 'base color'
        const midPoint = 0.6; 

        if (intensity < midPoint) {
            // Low to Mid: Fade from background to ColorBase
            // This ensures low values are visible as faint colors rather than invisible black
            const t = intensity / midPoint;
            red = lerp(bgR, colorBase[0], t);
            green = lerp(bgG, colorBase[1], t);
            blue = lerp(bgB, colorBase[2], t);
        } else {
            // Mid to High: Fade from ColorBase to White (Hot)
            const t = (intensity - midPoint) / (1 - midPoint);
            // Mix towards white for "heat" effect
            red = lerp(colorBase[0], 255, t);
            green = lerp(colorBase[1], 255, t);
            blue = lerp(colorBase[2], 255, t);
        }

        ctx.fillStyle = `rgb(${Math.floor(red)}, ${Math.floor(green)}, ${Math.floor(blue)})`;

        ctx.fillRect(
          c * cellSize + gap, 
          r * cellSize + gap, 
          cellSize - gap * 2, 
          cellSize - gap * 2
        );
      });
    });

  }, [adjacency, colorBase]);

  return (
    <div className="relative w-full aspect-square bg-slate-950 border border-slate-800 rounded overflow-hidden shadow-inner group">
      <canvas 
        ref={canvasRef}
        width={320}
        height={320}
        className="w-full h-full object-contain"
        style={{ imageRendering: 'pixelated' }}
      />
      {/* Subtle scanline/grid overlay */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(15,23,42,0.1)_50%,rgba(0,0,0,0.2)_50%)] bg-[length:100%_4px] opacity-50" />
      <div className="absolute inset-0 pointer-events-none ring-1 ring-inset ring-white/10 rounded" />
    </div>
  );
};

