import { useState, useEffect, useRef, useCallback } from 'react';
import { StrategyType, SimulationState, StrategyData, POPULATION_SIZE } from '../types';
import { createInitialPopulation, evolvePopulation, generateAdjacency, computeFitness, computeModularity } from '../utils/simulation';

const HISTORY_LENGTH = 50;

export const useExperiment = () => {
  const [simulationState, setSimulationState] = useState<SimulationState | null>(null);
  const stateRef = useRef<SimulationState | null>(null);
  const frameIdRef = useRef<number>(0);
  const [isRunning, setIsRunning] = useState(true);

  // Initialization helper
  const initializeState = useCallback(() => {
    const initialStrategies = Object.values(StrategyType).reduce((acc, type) => {
      const pop = createInitialPopulation(POPULATION_SIZE);
      const adj = generateAdjacency(pop);
      const rawFitness = computeFitness(pop);
      const mod = computeModularity(adj);

      // Initial fitness calculation with modularity boost
      const weightedFitness = rawFitness * (1 + mod);

      acc[type] = {
        type,
        population: pop,
        fitness: weightedFitness,
        modularity: mod,
        adjacency: adj,
        fitnessHistory: Array(HISTORY_LENGTH).fill(0)
      };
      return acc;
    }, {} as Record<StrategyType, StrategyData>);

    const initialState: SimulationState = {
      generation: 0,
      strategies: initialStrategies,
      metrics: {
        topoLead: 0,
        modularityScore: 0,
        thesisProgress: 0
      },
      isRunning: true
    };

    stateRef.current = initialState;
    setSimulationState(initialState);
  }, []);

  // Initialize once
  useEffect(() => {
    initializeState();
  }, [initializeState]);

  const tick = useCallback(() => {
    if (!stateRef.current || !stateRef.current.isRunning) return;

    const currentStrategies = stateRef.current.strategies;
    const nextStrategies = {} as Record<StrategyType, StrategyData>;
    let topoFitness = 0;
    let maxOtherFitness = 0;
    let topoModularity = 0;

    // Evolve each strategy
    Object.values(StrategyType).forEach(type => {
      const prev = currentStrategies[type];
      const nextPop = evolvePopulation(prev.population, type);
      const rawFitness = computeFitness(nextPop);
      const nextAdj = generateAdjacency(nextPop);
      const nextModularity = computeModularity(nextAdj);

      // CRITICAL UPDATE: Modularity as a Fitness Multiplier
      // This enforces the "Genomic Compression" thesis:
      // Structure (Modularity) reduces metabolic cost, effectively boosting fitness.
      // Strategies with high modularity will now statistically dominate over time.
      const adjustedFitness = rawFitness * (1 + nextModularity * 1.5);

      const nextHistory = [...prev.fitnessHistory, adjustedFitness].slice(-HISTORY_LENGTH);

      nextStrategies[type] = {
        type,
        population: nextPop,
        fitness: adjustedFitness,
        modularity: nextModularity,
        adjacency: nextAdj,
        fitnessHistory: nextHistory
      };

      if (type === StrategyType.Topological) {
        topoFitness = adjustedFitness;
        topoModularity = nextModularity;
      } else {
        maxOtherFitness = Math.max(maxOtherFitness, adjustedFitness);
      }
    });

    // Modified Metric: Slower convergence logic
    const topoLead = topoFitness - maxOtherFitness;

    // Logic:
    // 1. Momentum: 0.96 decay (slower decay to prevent jitter)
    // 2. Impulse: 
    //    - Fitness Lead * 25 (Significant reward for being the fittest)
    //    - Modularity * 1.5 (Consistent small reward for structure)
    //    - Resistance: -2 (Constant drag to prevent reaching 100% too easily)
    const impulse = (topoLead * 25) + (topoModularity * 1.5) - 2;

    const thesisProgress = Math.min(100, Math.max(0, 
      stateRef.current.metrics.thesisProgress * 0.96 + impulse
    ));

    const nextState: SimulationState = {
      generation: stateRef.current.generation + 1,
      strategies: nextStrategies,
      metrics: {
        topoLead,
        modularityScore: topoModularity,
        thesisProgress
      },
      isRunning: stateRef.current.isRunning
    };

    stateRef.current = nextState;
    setSimulationState(nextState);

    frameIdRef.current = requestAnimationFrame(tick);
  }, []);

  // Loop management
  useEffect(() => {
    if (isRunning) {
        frameIdRef.current = requestAnimationFrame(tick);
    }
    return () => cancelAnimationFrame(frameIdRef.current);
  }, [tick, isRunning]);

  const togglePause = () => {
    if (stateRef.current) {
        stateRef.current.isRunning = !stateRef.current.isRunning;
        setSimulationState({...stateRef.current});
        setIsRunning(stateRef.current.isRunning);
    }
  };

  const resetExperiment = () => {
      initializeState();
      setIsRunning(true);
  };

  return { state: simulationState, togglePause, resetExperiment };
};

import { StrategyType, MATRIX_SIZE } from '../types';

export function createInitialPopulation(size: number): number[] {
  // We utilize a 1:1 mapping between population genes and matrix cells (16x16=256)
  // to ensure spatial strategies function correctly without aliasing.
  return Array(size).fill(0).map(() => Math.random() * 2 - 1);
}

export function computeFitness(pop: number[]): number {
  if (pop.length === 0) return 0;
  const mean = pop.reduce((a, b) => a + b, 0) / pop.length;
  const variance = pop.reduce((a, b) => a + (b - mean) ** 2, 0) / pop.length;
  // Adjusted fitness: Reward high variance (information) and positive signal
  return (mean * 0.5 + Math.sqrt(variance) * 0.5);
}

export function generateAdjacency(pop: number[]): number[][] {
  const n = MATRIX_SIZE;
  const adj = Array(n).fill(0).map(() => Array(n).fill(0));

  for (let i = 0; i < n * n; i++) {
    const row = Math.floor(i / n);
    const col = i % n;
    // Use modulo if population < n*n, though we aim for 1:1
    const geneVal = pop[i % pop.length];
    adj[row][col] = Math.max(0, geneVal);
  }

  // Normalize row sums to make it look like probability/interaction matrix
  // But keep relative intensity for visual impact
  const rowSums = adj.map(row => row.reduce((a, b) => a + b, 0));
  for (let i = 0; i < n; i++) {
    if (rowSums[i] > 0.001) {
      for (let j = 0; j < n; j++) {
        // Soft normalization to preserve some absolute intensity diffs
        adj[i][j] = adj[i][j] / (rowSums[i] * 0.8 + 0.2); 
      }
    }
  }
  return adj;
}

export function computeModularity(adj: number[][]): number {
  const n = adj.length;
  let score = 0;
  let totalWeight = 0;

  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      const weight = adj[i][j];
      totalWeight += weight;

      const dist = Math.abs(i - j);
      // Reward connections close to diagonal (TADs)
      // Penalize long range
      if (dist <= 3) {
        score += weight * (4 - dist); // High reward for very close
      } else {
        score -= weight * (dist * 0.5); // Penalty scales with distance
      }
    }
  }

  return totalWeight > 0 ? Math.max(0, score / totalWeight) : 0;
}

export function evolvePopulation(pop: number[], strategy: StrategyType): number[] {
  const nextPop = [...pop];
  const n = MATRIX_SIZE;

  for (let i = 0; i < nextPop.length; i++) {
    let gene = nextPop[i];

    // Basic thermal noise
    // Increased noise for all strategies to create more fluctuation
    gene += (Math.random() - 0.5) * 0.2;

    // Derived spatial coordinates (assuming row-major filling)
    const row = Math.floor(i / n);
    const col = i % n;
    const dist = Math.abs(row - col);

    if (strategy === StrategyType.Topological) {
      // Topological: Enforce diagonal dominance (TAD-like structures)
      // Expanded radius to 4 to match Modularity scoring function
      if (dist < 4) {
        gene += 0.05; // Slightly reduced growth pressure
      } else {
        gene *= 0.90; // Stronger decay pressure to clear noise
      }

      // Periodically boost random diagonal blocks to simulate TAD formation
      if (Math.random() < 0.02 && dist < 5) {
         gene += 0.6;
      }

    } else if (strategy === StrategyType.Hierarchical) {
       // Hierarchical: Quantize into discrete levels
       const levels = 4;
       const target = Math.round(gene * levels) / levels;
       gene = gene + (target - gene) * 0.15; // Stronger pull to structure

    } else if (strategy === StrategyType.Flat) {
       // Flat: Strong reversion to mean
       gene = gene * 0.9 + (Math.random() - 0.5) * 0.05;
       gene = Math.max(-0.2, Math.min(0.2, gene));
    } else {
       // Direct: Unconstrained
       // Occasional bursts of signal to compete
       if (Math.random() < 0.005) gene = 1;
    }

    // Hard Bounds
    nextPop[i] = Math.max(-1, Math.min(1, gene));
  }

  return nextPop;
}

