import React, { useRef, useMemo, useState, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sphere, Line, Billboard, Text } from '@react-three/drei';
import * as THREE from 'three';
import { MATRIX_SIZE } from '../types';

interface DNAVisualizerProps {
  adjacency: number[][];
  colorBase: [number, number, number];
}

// Physics Constants
const NUM_PARTICLES = MATRIX_SIZE;
const REPULSION = 1.0;
const DAMPING = 0.95;
const BACKBONE_LENGTH = 1.5;

const PolymerSimulation = ({ adjacency, colorBase }: DNAVisualizerProps) => {
  // Store positions in a mutable ref to avoid React render loop overhead for physics
  const positions = useRef<THREE.Vector3[]>([]);
  const velocities = useRef<THREE.Vector3[]>([]);
  const lineRef = useRef<any>(null);
  const sphereRefs = useRef<(THREE.Mesh | null)[]>([]);

  // Initialize random positions if empty
  useMemo(() => {
    if (positions.current.length === 0) {
      for (let i = 0; i < NUM_PARTICLES; i++) {
        // Start in a loose cloud
        positions.current.push(new THREE.Vector3(
          (Math.random() - 0.5) * 10,
          (Math.random() - 0.5) * 10,
          (Math.random() - 0.5) * 10
        ));
        velocities.current.push(new THREE.Vector3(0, 0, 0));
      }
    }
  }, []);

  // Physics Loop
  useFrame(() => {
    const pos = positions.current;
    const vel = velocities.current;

    // 1. Calculate Forces
    for (let i = 0; i < NUM_PARTICLES; i++) {
      const force = new THREE.Vector3(0, 0, 0);

      // A. Center Gravity (Keep it in view)
      force.add(pos[i].clone().multiplyScalar(-0.01));

      // B. Repulsion (Nodes push apart so they don't collapse to a singularity)
      for (let j = 0; j < NUM_PARTICLES; j++) {
        if (i === j) continue;
        const diff = new THREE.Vector3().subVectors(pos[i], pos[j]);
        const dist = diff.length();
        if (dist < 0.1) diff.set(Math.random(), Math.random(), Math.random()); // Prevent division by zero

        // Coulomb-like repulsion
        if (dist < 4.0) {
            force.add(diff.normalize().multiplyScalar(REPULSION / (dist * dist + 0.1)));
        }
      }

      // C. Backbone Constraints (i connects to i+1)
      // This represents the physical DNA strand continuity
      if (i > 0) {
          const prev = i - 1;
          const diff = new THREE.Vector3().subVectors(pos[prev], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * 0.2));
      }
      if (i < NUM_PARTICLES - 1) {
          const next = i + 1;
          const diff = new THREE.Vector3().subVectors(pos[next], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * 0.2));
      }

      // D. MATRIX FORCES (The Evolutionary Intelligence)
      // High adjacency weight = Strong attraction (TAD formation)
      for (let j = 0; j < NUM_PARTICLES; j++) {
          if (i === j) continue;

          const weight = adjacency[i][j];
          if (weight > 0.1) {
              const diff = new THREE.Vector3().subVectors(pos[j], pos[i]);
              const dist = diff.length();

              // Target distance decreases as weight increases
              const targetDist = 5.0 * (1.0 - weight); 

              // Spring force
              const displacement = dist - targetDist;
              force.add(diff.normalize().multiplyScalar(displacement * 0.05 * weight));
          }
      }

      // Apply Force to Velocity
      vel[i].add(force);
      vel[i].multiplyScalar(DAMPING); // Friction
    }

    // 2. Update Positions
    for (let i = 0; i < NUM_PARTICLES; i++) {
      pos[i].add(vel[i]);

      // Update visual objects
      if (sphereRefs.current[i]) {
          sphereRefs.current[i]!.position.copy(pos[i]);
      }
    }

    // Update Connecting Line
    if (lineRef.current) {
        lineRef.current.setPoints(pos);
    }
  });

  const particleColor = `rgb(${colorBase[0]}, ${colorBase[1]}, ${colorBase[2]})`;

  return (
    <group>
      {/* The Backbone Line */}
      <Line 
        ref={lineRef}
        points={positions.current}
        color={particleColor}
        lineWidth={2}
        transparent
        opacity={0.4}
      />

      {/* The Nodes (TADs) */}
      {positions.current.map((_, i) => (
        <mesh 
            key={i} 
            ref={(el) => (sphereRefs.current[i] = el)}
            position={[0,0,0]} // Updated by simulation
        >
            <sphereGeometry args={[0.3, 16, 16]} />
            <meshStandardMaterial 
                color={particleColor} 
                emissive={particleColor}
                emissiveIntensity={2}
                toneMapped={false}
            />
        </mesh>
      ))}

      {/* Start/End Labels */}
      <Billboard position={positions.current[0]}>
         <Text fontSize={0.5} color="white" anchorX="center" anchorY="middle" outlineWidth={0.05} outlineColor="#000000">
            5'
         </Text>
      </Billboard>

      <Billboard position={positions.current[NUM_PARTICLES-1]}>
         <Text fontSize={0.5} color="white" anchorX="center" anchorY="middle" outlineWidth={0.05} outlineColor="#000000">
            3'
         </Text>
      </Billboard>
    </group>
  );
};

const DNAVisualizer: React.FC<DNAVisualizerProps> = (props) => {
  return (
    <div className="w-full h-full bg-slate-950 relative rounded overflow-hidden shadow-inner group">
      <Canvas camera={{ position: [0, 0, 20], fov: 45 }}>
        <fog attach="fog" args={['#020617', 10, 40]} />
        <ambientLight intensity={0.2} />
        <pointLight position={[10, 10, 10]} intensity={1} />
        <pointLight position={[-10, -10, -10]} intensity={0.5} color="blue" />

        <PolymerSimulation {...props} />

        <OrbitControls 
            autoRotate 
            autoRotateSpeed={1.5} 
            enablePan={false}
            minDistance={5}
            maxDistance={30}
        />
      </Canvas>

      {/* Overlay UI */}
      <div className="absolute bottom-3 left-3 pointer-events-none">
         <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
            <span className="text-[10px] font-mono text-red-400">PHYSICS_ENGINE: ACTIVE</span>
         </div>
      </div>
    </div>
  );
};

