import { useState, useEffect, useRef, useCallback } from 'react';
import { StrategyType, SimulationState, StrategyData, POPULATION_SIZE, ClusterNode } from '../types';
import { createInitialPopulation, evolvePopulation, generateAdjacency, computeFitness, computeModularity } from '../utils/simulation';

const HISTORY_LENGTH = 50;
const TELEMETRY_PORT = 3333;

const INITIAL_NODES: ClusterNode[] = [
  { id: 'n1', name: 'muladhara', status: 'active', runtime: '8h 47min', generation: 10, cpuUsage: 1083, memoryUsage: 139, temperature: 82 },
  { id: 'n2', name: 'svadhisthana', status: 'syncing', runtime: '4h 51min', generation: 0, cpuUsage: 110, memoryUsage: 97, temperature: 45 },
  { id: 'n3', name: 'manipura', status: 'syncing', runtime: '4h 54min', generation: 0, cpuUsage: 346, memoryUsage: 94, temperature: 58 },
  { id: 'n4', name: 'anahata', status: 'syncing', runtime: '4h 52min', generation: 0, cpuUsage: 101, memoryUsage: 91, temperature: 42 },
  { id: 'n5', name: 'vishuddha', status: 'standby', runtime: '0h 00min', generation: 0, cpuUsage: 45, memoryUsage: 32, temperature: 28 },
