const ClusterTopology: React.FC<{ nodes: ClusterNode[] }> = ({ nodes }) => {
  const radius = 80;
  const cx = 150;
  const cy = 130; // Shifted down slightly to accommodate top label

  // Calculate pentagon positions
  const points = useMemo(() => {
    return nodes.map((_, i) => {
      const angle = -Math.PI / 2 + (i * 2 * Math.PI) / nodes.length;
      return {
        x: cx + radius * Math.cos(angle),
        y: cy + radius * Math.sin(angle),
        angle
      };
    });
  }, [nodes]);

  // Generate full mesh connections (every node to every other node)
  const connections = useMemo(() => {
    const lines = [];
    for (let i = 0; i < points.length; i++) {
      for (let j = i + 1; j < points.length; j++) {
        lines.push({
          x1: points[i].x,
          y1: points[i].y,
          x2: points[j].x,
          y2: points[j].y,
          id: `${i}-${j}`
        });
      }
    }
    return lines;
  }, [points]);

  return (
    <div className="flex flex-col items-center justify-center p-4 bg-slate-950/30 rounded border border-slate-800 mb-4 relative overflow-hidden">
      <div className="absolute top-2 left-3 text-[10px] font-mono text-slate-500 flex items-center gap-1">
         <Network size={10} />
         RDMA_MESH::ACTIVE
      </div>

      <svg width="300" height="260" className="overflow-visible">
        <defs>
          <linearGradient id="lineGradient" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="rgba(99, 102, 241, 0.1)" />
            <stop offset="50%" stopColor="rgba(99, 102, 241, 0.8)" />
            <stop offset="100%" stopColor="rgba(99, 102, 241, 0.1)" />
          </linearGradient>
          <filter id="glow">
            <feGaussianBlur stdDeviation="2.5" result="coloredBlur"/>
            <feMerge>
                <feMergeNode in="coloredBlur"/>
                <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
        </defs>

        {/* Connections */}
        {connections.map((line, i) => (
          <g key={line.id}>
             {/* Static dim line */}
             <line 
                x1={line.x1} y1={line.y1} x2={line.x2} y2={line.y2} 
                stroke="#1e293b" 
                strokeWidth="1" 
             />
             {/* Animated data packet line */}
             <line 
                x1={line.x1} y1={line.y1} x2={line.x2} y2={line.y2} 
                stroke="url(#lineGradient)" 
                strokeWidth="2"
                strokeLinecap="round"
                className="opacity-60"
             >
                <animate 
                   attributeName="stroke-dasharray" 
                   values="0,150;150,0;0,150" 
                   dur={`${2 + (i % 3) * 0.5}s`} 
                   repeatCount="indefinite" 
                />
                 <animate 
                   attributeName="stroke-opacity" 
                   values="0.2;1;0.2" 
                   dur={`${1.5 + (i % 2)}s`} 
                   repeatCount="indefinite" 
                />
             </line>
          </g>
        ))}

        {/* Nodes */}
        {points.map((p, i) => {
          const node = nodes[i];
          const isLeader = i === 0; // Muladhara
          const isActive = node.status === 'active';

          return (
            <g key={node.id} className="cursor-default group">
              {/* Outer Glow Ring */}
              <circle 
                cx={p.x} cy={p.y} r="16" 
                fill="none" 
                stroke={isLeader ? '#10b981' : '#6366f1'} 
                strokeWidth="1"
                className={isActive ? "animate-ping opacity-20" : "opacity-0"}
                style={{ animationDuration: '3s' }}
              />

              {/* Core Node */}
              <circle 
                cx={p.x} cy={p.y} r="6" 
                fill="#0f172a" 
                stroke={isLeader ? '#10b981' : (isActive ? '#6366f1' : '#475569')} 
                strokeWidth="2" 
                filter="url(#glow)"
              />

              {/* Status Dot */}
              <circle 
                cx={p.x} cy={p.y} r="2" 
                fill={isLeader ? '#10b981' : (isActive ? '#6366f1' : '#475569')} 
              />

              {/* Labels - positioned based on angle to avoid overlap */}
              <text 
                x={p.x + (Math.cos(p.angle) * 25)} 
                y={p.y + (Math.sin(p.angle) * 25)} 
                textAnchor={Math.cos(p.angle) > 0.1 ? "start" : Math.cos(p.angle) < -0.1 ? "end" : "middle"} 
                alignmentBaseline={Math.sin(p.angle) > 0.1 ? "hanging" : "baseline"}
                fill={isLeader ? '#10b981' : '#94a3b8'} 
                className="text-[8px] font-mono uppercase font-bold tracking-wider"
                style={{ textShadow: '0 0 5px rgba(0,0,0,0.8)' }}
              >
                {node.name}
              </text>

              {/* Metric Label (CPU) */}
              <text 
                x={p.x + (Math.cos(p.angle) * 25)} 
                y={p.y + (Math.sin(p.angle) * 25) + 10} 
                textAnchor={Math.cos(p.angle) > 0.1 ? "start" : Math.cos(p.angle) < -0.1 ? "end" : "middle"} 
                alignmentBaseline={Math.sin(p.angle) > 0.1 ? "hanging" : "baseline"}
                fill="#475569" 
                className="text-[6px] font-mono"
              >
                {node.cpuUsage}% LOAD
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
};

