import React, { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Billboard, Text, Tube, Sphere } from '@react-three/drei';
import * as THREE from 'three';
import { MATRIX_SIZE } from '../types';
import { Play, Pause, MousePointer2, Scan } from 'lucide-react';

// Standard Three.js elements
const Group = 'group' as any;
const Fog = 'fog' as any;
const AmbientLight = 'ambientLight' as any;
const PointLight = 'pointLight' as any;
const DirectionalLight = 'directionalLight' as any;

interface DNAVisualizerProps {
  adjacency: number[][];
  colorBase: [number, number, number];
}

// Physics Constants
const NUM_PARTICLES = MATRIX_SIZE;
const REPULSION = 1.0;
const DAMPING = 0.95;
const BACKBONE_LENGTH = 1.5;

// The Cohesin Ring Animation Component
const CohesinComplex = ({ path }: { path: THREE.CatmullRomCurve3 }) => {
  const ringRef = useRef<THREE.Group>(null);
  const [t, setT] = useState(0);
  const direction = useRef(1);

  useFrame((state, delta) => {
    if (!ringRef.current || !path) return;

    // Animate t back and forth
    let nextT = t + (delta * 0.1 * direction.current);
    if (nextT > 1) { nextT = 1; direction.current = -1; }
    if (nextT < 0) { nextT = 0; direction.current = 1; }
    setT(nextT);

    const point = path.getPointAt(nextT);
    const tangent = path.getTangentAt(nextT);

    ringRef.current.position.copy(point);

    // Orient ring to tangent
    const up = new THREE.Vector3(0, 1, 0);
    const axis = new THREE.Vector3().crossVectors(up, tangent).normalize();
    const radians = Math.acos(up.dot(tangent));
    ringRef.current.quaternion.setFromAxisAngle(axis, radians);
  });

  return (
    <Group ref={ringRef}>
       {/* The Cohesin Ring (Torus) */}
       <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[0.6, 0.15, 16, 32]} />
          <meshStandardMaterial color="#f472b6" emissive="#f472b6" emissiveIntensity={0.5} metalness={0.8} roughness={0.2} />
       </mesh>
       {/* Molecular Glow */}
       <pointLight color="#f472b6" intensity={1} distance={3} />

       <Billboard position={[0, 1.2, 0]}>
          <Text fontSize={0.3} color="#f472b6" outlineWidth={0.02}>
             COHESIN_MOTOR
          </Text>
       </Billboard>
    </Group>
  );
};

const ChromatinSpaghetti = ({ positions, colorBase }: { positions: React.MutableRefObject<THREE.Vector3[]>, colorBase: [number, number, number] }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  // Create a persistent curve object
  const curve = useMemo(() => new THREE.CatmullRomCurve3(
      new Array(NUM_PARTICLES).fill(0).map(() => new THREE.Vector3()), 
      false, 
      'catmullrom', 
      0.5
  ), []);

  useFrame(() => {
    if (!meshRef.current || positions.current.length === 0) return;

    // 1. Update Curve Control Points from Physics
    // We strictly copy values to avoid reference issues if the array is replaced
    for(let i=0; i<NUM_PARTICLES; i++) {
        curve.points[i].copy(positions.current[i]);
    }

    // 2. Force Geometry Update
    // TubeGeometry does not update automatically when curve points change.
    // We must rebuild it. For low poly counts (16 points, 64 segments), this is performant.
    if (meshRef.current.geometry) meshRef.current.geometry.dispose();
    meshRef.current.geometry = new THREE.TubeGeometry(curve, 128, 0.25, 8, false);
  });

  const particleColor = `rgb(${colorBase[0]}, ${colorBase[1]}, ${colorBase[2]})`;

  return (
    <Group>
        <mesh ref={meshRef}>
            <meshStandardMaterial 
                color={particleColor} 
                roughness={0.4} 
                metalness={0.6} 
                emissive={particleColor}
                emissiveIntensity={0.2}
            />
        </mesh>
        <CohesinComplex path={curve} />
    </Group>
  );
};


const PolymerSimulation = ({ adjacency, colorBase }: DNAVisualizerProps) => {
  // Store positions in a mutable ref to avoid React render loop overhead for physics
  const positions = useRef<THREE.Vector3[]>([]);
  const velocities = useRef<THREE.Vector3[]>([]);

  // Initialize random positions if empty
  useMemo(() => {
    if (positions.current.length === 0) {
      for (let i = 0; i < NUM_PARTICLES; i++) {
        // Start in a loose cloud
        positions.current.push(new THREE.Vector3(
          (Math.random() - 0.5) * 12,
          (Math.random() - 0.5) * 12,
          (Math.random() - 0.5) * 12
        ));
        velocities.current.push(new THREE.Vector3(0, 0, 0));
      }
    }
  }, []);

  // Physics Loop
  useFrame(() => {
    const pos = positions.current;
    const vel = velocities.current;

    for (let i = 0; i < NUM_PARTICLES; i++) {
      const force = new THREE.Vector3(0, 0, 0);

      // A. Center Gravity (Keep it in view)
      force.add(pos[i].clone().multiplyScalar(-0.005));

      // B. Repulsion (Volume exclusion)
      for (let j = 0; j < NUM_PARTICLES; j++) {
        if (i === j) continue;
        const diff = new THREE.Vector3().subVectors(pos[i], pos[j]);
        const dist = diff.length();
        if (dist < 0.1) diff.set(Math.random(), Math.random(), Math.random());

        if (dist < 3.0) {
            force.add(diff.normalize().multiplyScalar(REPULSION / (dist * dist + 0.1)));
        }
      }

      // C. Backbone Constraints (i connects to i+1)
      if (i > 0) {
          const prev = i - 1;
          const diff = new THREE.Vector3().subVectors(pos[prev], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * 0.15));
      }
      if (i < NUM_PARTICLES - 1) {
          const next = i + 1;
          const diff = new THREE.Vector3().subVectors(pos[next], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * 0.15));
      }

      // D. MATRIX FORCES (The Evolutionary Intelligence)
      for (let j = 0; j < NUM_PARTICLES; j++) {
          if (i === j) continue;
          const weight = adjacency[i][j];
          if (weight > 0.1) {
              const diff = new THREE.Vector3().subVectors(pos[j], pos[i]);
              const dist = diff.length();
              const targetDist = 4.0 * (1.0 - weight); 
              const displacement = dist - targetDist;
              force.add(diff.normalize().multiplyScalar(displacement * 0.04 * weight));
          }
      }

      vel[i].add(force);
      vel[i].multiplyScalar(DAMPING); 
    }

    for (let i = 0; i < NUM_PARTICLES; i++) {
      pos[i].add(vel[i]);
    }
  });

  return (
      <ChromatinSpaghetti positions={positions} colorBase={colorBase} />
  );
};

const DNAVisualizer: React.FC<DNAVisualizerProps> = (props) => {
  const [autoRotate, setAutoRotate] = useState(true);

  return (
    <div className="w-full h-full bg-slate-950 relative rounded overflow-hidden shadow-inner group border border-slate-800">
      <Canvas 
        camera={{ position: [0, 0, 24], fov: 40 }}
