import React, { useRef, useEffect } from 'react';
import { MATRIX_SIZE } from '../types';

interface HeatmapProps {
  adjacency: number[][];
  colorBase: [number, number, number]; // RGB tuple
}

const Heatmap: React.FC<HeatmapProps> = ({ adjacency, colorBase }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear background with deep dark slate
    ctx.fillStyle = '#020617'; 
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const cellSize = canvas.width / MATRIX_SIZE;
    const gap = 1;

    // Linear interpolation for individual channels
    const lerp = (start: number, end: number, t: number) => start + (end - start) * t;

    // RGB Interpolation helper
    const lerpColor = (c1: number[], c2: number[], t: number) => {
        return [
            Math.round(lerp(c1[0], c2[0], t)),
            Math.round(lerp(c1[1], c2[1], t)),
            Math.round(lerp(c1[2], c2[2], t))
        ];
    };

    adjacency.forEach((row, r) => {
      row.forEach((val, c) => {
        // Clamp raw value
        const raw = Math.min(1, Math.max(0, val));

        // Perceptual scaling: Cube root (0.33) lifts low values significantly more than 0.45 or linear
        // This simulates the visibility of log-scale data without losing linear relationships entirely
        const t = Math.pow(raw, 0.33); 

        // Define Dynamic Gradient Stops (Plasma-like luminance curve but hue-preserved)
        // 0.00: Background (Slate-950)
        // 0.25: Deep Shadow (Saturated, Dark version of Base)
        // 0.50: Base Color (Midtone)
        // 0.85: High Heat (Base mixed with White/Bright)
        // 1.00: Core White

        const bg = [2, 6, 23]; // #020617

        // Deep: 40% luminance of base. This creates a rich "shadow" rather than a fade to black.
        const deep = colorBase.map(v => Math.floor(v * 0.4));

        // Mid: The actual strategy color
        const mid = colorBase;

        // Hot: Desaturated bright version (80% Base + 20% White boost) -> Then clamped
        // Actually, let's go for a "Lava" effect: Mix heavily with white/yellow
        const hot = colorBase.map(v => Math.min(255, v * 0.3 + 255 * 0.7));

        const core = [255, 255, 255];

        let finalColor;

        if (t < 0.25) {
            finalColor = lerpColor(bg, deep, t / 0.25);
        } else if (t < 0.5) {
            finalColor = lerpColor(deep, mid, (t - 0.25) / 0.25);
        } else if (t < 0.85) {
            finalColor = lerpColor(mid, hot, (t - 0.5) / 0.35);
        } else {
            finalColor = lerpColor(hot, core, (t - 0.85) / 0.15);
        }

        ctx.fillStyle = `rgb(${finalColor[0]}, ${finalColor[1]}, ${finalColor[2]})`;

        ctx.fillRect(
          c * cellSize + gap, 
          r * cellSize + gap, 
          cellSize - gap * 2, 
          cellSize - gap * 2
        );
      });
    });

  }, [adjacency, colorBase]);

  return (
    <div className="relative w-full aspect-square bg-slate-950 border border-slate-800 rounded overflow-hidden shadow-inner group">
      <canvas 
        ref={canvasRef}
        width={320}
        height={320}
        className="w-full h-full object-contain"
        style={{ imageRendering: 'pixelated' }}
      />
      {/* Tech Overlay: Scanline + Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(15,23,42,0.1)_50%,rgba(0,0,0,0.2)_50%)] bg-[length:100%_4px] opacity-30" />
      <div className="absolute inset-0 pointer-events-none ring-1 ring-inset ring-white/10 rounded" />
    </div>
  );
};

