import { StrategyType, MATRIX_SIZE } from '../types';

export function createInitialPopulation(size: number): number[] {
  // We utilize a 1:1 mapping between population genes and matrix cells (16x16=256)
  return Array(size).fill(0).map(() => Math.random() * 2 - 1);
}

// NEW: Calculate the energy cost of the structure
// DNA creates "Topologically Associating Domains" (TADs) to minimize the wire-length between interacting genes.
// Random structures have high wire-length -> High Metabolic Cost -> Extinction.
export function computeMetabolicCost(adj: number[][]): number {
  const n = adj.length;
  let totalCost = 0;
  let totalSignal = 0;

  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      const weight = adj[i][j];
      if (weight > 0.05) {
        const dist = Math.abs(i - j);
        // Cost increases non-linearly with distance (Square law for 3D folding simulation)
        // Connecting distant parts of the genome is expensive!
        totalCost += weight * (dist * dist);
        totalSignal += weight;
      }
    }
  }

  // Normalized cost per unit of signal
  return totalSignal > 0 ? (totalCost / totalSignal) / (n * n) : 0;
}

export function computeFitness(pop: number[], adj: number[][]): number {
  if (pop.length === 0) return 0;

  // 1. Raw Vitality (Signal Strength)
  const mean = pop.reduce((a, b) => a + b, 0) / pop.length;
  const variance = pop.reduce((a, b) => a + (b - mean) ** 2, 0) / pop.length;
  const vitality = (mean * 0.5 + Math.sqrt(variance) * 0.5);

  // 2. Metabolic Cost (The Entropy Tax)
  // "There is a real and significant cost to all atomic decisions."
  const cost = computeMetabolicCost(adj);

  // 3. Efficiency Ratio
  // Fitness is Vitality minus the Cost to maintain it.
  // Inefficient strategies (High Cost) will yield negative fitness eventually.
  return vitality - (cost * 2.5); 
}

export function generateAdjacency(pop: number[]): number[][] {
  const n = MATRIX_SIZE;
  const adj = Array(n).fill(0).map(() => Array(n).fill(0));

  for (let i = 0; i < n * n; i++) {
    const row = Math.floor(i / n);
    const col = i % n;
    const geneVal = pop[i % pop.length];
    adj[row][col] = Math.max(0, geneVal);
  }

  const rowSums = adj.map(row => row.reduce((a, b) => a + b, 0));
  for (let i = 0; i < n; i++) {
    if (rowSums[i] > 0.001) {
      for (let j = 0; j < n; j++) {
        adj[i][j] = adj[i][j] / (rowSums[i] * 0.8 + 0.2); 
      }
    }
  }
  return adj;
}

export function computeModularity(adj: number[][]): number {
  const n = adj.length;
  let score = 0;
  let totalWeight = 0;

  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      const weight = adj[i][j];
      totalWeight += weight;
      const dist = Math.abs(i - j);

      if (dist <= 3) {
        score += weight * (4 - dist); 
      } else {
        score -= weight * (dist * 0.5); 
      }
    }
  }

  return totalWeight > 0 ? Math.max(0, score / totalWeight) : 0;
}

export function evolvePopulation(pop: number[], strategy: StrategyType): number[] {
  const nextPop = [...pop];
  const n = MATRIX_SIZE;

  // Define fixed CTCF Boundary Sites for PNAS 2016 Model simulation
  // Boundaries at indices 4, 8, 12 create 4 distinct TADs of size 4.
  const BOUNDARIES = [4, 8, 12]; 

  for (let i = 0; i < nextPop.length; i++) {
    let gene = nextPop[i];

    // Thermal Noise (Entropy)
    gene += (Math.random() - 0.5) * 0.2;

    const row = Math.floor(i / n);
    const col = i % n;
    const dist = Math.abs(row - col);

    if (strategy === StrategyType.Topological) {
      // PNAS 2016 MODEL: LOOP EXTRUSION
      // 1. Local interactions (loops) are favored.
      // 2. Interactions crossing a Boundary (CTCF) are blocked.

      let crossesBoundary = false;
      // Check if the path between row and col crosses a boundary index
      const min = Math.min(row, col);
      const max = Math.max(row, col);
      for (const b of BOUNDARIES) {
          if (min < b && max >= b) {
              crossesBoundary = true;
              break;
          }
      }

      if (crossesBoundary) {
          // Boundary Insulation: Heavily penalize crossing connections
          gene *= 0.1; 
      } else {
          // Within TAD: Enhance loop formation
          if (dist < 4) {
             gene += 0.08; 
          }
      }

      // Cleanup faint signals to enforce sparsity
      if (gene < 0.2) gene *= 0.8;

    } else if (strategy === StrategyType.Hierarchical) {
       const levels = 4;
       const target = Math.round(gene * levels) / levels;
       gene = gene + (target - gene) * 0.15;

    } else if (strategy === StrategyType.Flat) {
       gene = gene * 0.9 + (Math.random() - 0.5) * 0.05;
       gene = Math.max(-0.2, Math.min(0.2, gene));
    } else {
       // Direct / Random Strategy
       if (Math.random() < 0.005) gene = 1;
    }

    nextPop[i] = Math.max(-1, Math.min(1, gene));
  }

  return nextPop;
}

import React, { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Billboard, Text, Tube, Sphere } from '@react-three/drei';
import * as THREE from 'three';
import { MATRIX_SIZE } from '../types';
import { Play, Pause, MousePointer2, Scan } from 'lucide-react';

// Standard Three.js elements - explicitly cast to any to avoid TS intrinsic element issues in this setup
const Group = 'group' as any;
const Fog = 'fog' as any;
const AmbientLight = 'ambientLight' as any;
const PointLight = 'pointLight' as any;
const DirectionalLight = 'directionalLight' as any;
const Mesh = 'mesh' as any;
const TorusGeometry = 'torusGeometry' as any;
const MeshStandardMaterial = 'meshStandardMaterial' as any;
const GridHelper = 'gridHelper' as any;
const SphereGeometry = 'sphereGeometry' as any;

interface DNAVisualizerProps {
  adjacency: number[][];
  colorBase: [number, number, number];
}

// Physics Constants
const NUM_PARTICLES = MATRIX_SIZE;
const REPULSION = 1.0;
const DAMPING = 0.92;
const BACKBONE_LENGTH = 1.8;

// PNAS 2016 Model: CTCF Boundaries at 4, 8, 12
const BOUNDARIES = [4, 8, 12];

// The Cohesin Ring that clamps the loop base
const CohesinClamp = ({ position, rotation, active }: { position: THREE.Vector3, rotation: THREE.Quaternion, active: boolean }) => {
  return (
    <Group position={position} quaternion={rotation} visible={active}>
       {/* The Ring - Scaled to encompass two strands */}
       <Mesh rotation={[Math.PI / 2, 0, 0]}>
          <TorusGeometry args={[1.2, 0.25, 16, 32]} />
          <MeshStandardMaterial color="#ec4899" emissive="#ec4899" emissiveIntensity={active ? 1.0 : 0.2} toneMapped={false} />
       </Mesh>

       <PointLight color="#ec4899" intensity={active ? 3 : 0} distance={10} decay={2} />

       <Billboard position={[0, 2, 0]}>
          <Text fontSize={0.4} color="#fbcfe8" outlineWidth={0.02} outlineColor="#831843">
             COHESIN_MOTOR
          </Text>
          <Text position={[0, -0.5, 0]} fontSize={0.25} color="#ec4899">
             EXTRUDING_LOOP
          </Text>
       </Billboard>
    </Group>
  );
};

const ChromatinSpaghetti = ({ positions, colorBase, extrusionState }: { positions: React.MutableRefObject<THREE.Vector3[]>, colorBase: [number, number, number], extrusionState: React.MutableRefObject<any> }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const spheresRef = useRef<THREE.Group>(null);
  const cohesinRef = useRef<any>(null); // To store calculated position for the UI component

  // Create a persistent curve object
  const curve = useMemo(() => new THREE.CatmullRomCurve3(
      new Array(NUM_PARTICLES).fill(0).map(() => new THREE.Vector3()), 
      false, 
      'catmullrom', 
      0.5
  ), []);

  // Track the cohesin clamp transform
  const [clampPos, setClampPos] = useState(new THREE.Vector3(0,0,0));
  const [clampRot, setClampRot] = useState(new THREE.Quaternion());

  useFrame(() => {
    if (!meshRef.current || positions.current.length === 0) return;

    // 1. Update Curve Control Points
    for(let i=0; i<NUM_PARTICLES; i++) {
        curve.points[i].copy(positions.current[i]);
    }

    // 2. Force Geometry Update
    if (meshRef.current.geometry) meshRef.current.geometry.dispose();
    meshRef.current.geometry = new THREE.TubeGeometry(curve, 64, 0.35, 8, false); 

    // 3. Update Sphere Positions
    if (spheresRef.current) {
        spheresRef.current.children.forEach((child: any, i) => {
            if (positions.current[i]) {
                child.position.copy(positions.current[i]);

                // Color boundaries (CTCF) differently
                if (BOUNDARIES.includes(i)) {
                    child.scale.setScalar(1.5);
                    (child.material as any).color.set('#3b82f6');
                    (child.material as any).emissive.set('#3b82f6');
                } else {
                    child.scale.setScalar(1.0);
                }
            }
        });
    }

    // 4. Calculate Cohesin Clamp Position (Midpoint of extrusion feet)
    const state = extrusionState.current;
    if (state.active) {
        const left = positions.current[state.leftFoot];
        const right = positions.current[state.rightFoot];
        if (left && right) {
            const mid = new THREE.Vector3().addVectors(left, right).multiplyScalar(0.5);
            setClampPos(mid);

            // Orient to be perpendicular to the loop axis (rough approximation)
            // Axis from left to right foot
            const axis = new THREE.Vector3().subVectors(right, left).normalize();
            const up = new THREE.Vector3(0, 1, 0);
            const q = new THREE.Quaternion().setFromUnitVectors(up, axis);
            // Rotate 90 deg so the ring goes AROUND the axis
            const q2 = new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(1,0,0), Math.PI/2);
            q.multiply(q2);
            setClampRot(q);
        }
    }
  });

  const particleColor = `rgb(${colorBase[0]}, ${colorBase[1]}, ${colorBase[2]})`;
  const secondaryColor = `rgb(${Math.min(255, colorBase[0]+50)}, ${Math.min(255, colorBase[1]+50)}, ${Math.min(255, colorBase[2]+50)})`;

  return (
    <Group>
        <Mesh ref={meshRef}>
            <MeshStandardMaterial 
                color={particleColor} 
                roughness={0.2} 
                metalness={0.1} 
                emissive={particleColor}
                emissiveIntensity={0.6}
            />
        </Mesh>

        <Group ref={spheresRef}>
            {new Array(NUM_PARTICLES).fill(0).map((_, i) => (
                <Mesh key={i}>
                    <SphereGeometry args={[0.5, 16, 16]} />
                    <MeshStandardMaterial 
                        color={secondaryColor} 
                        emissive={secondaryColor}
                        emissiveIntensity={0.4}
                        roughness={0.3}
                    />
                </Mesh>
            ))}
        </Group>

        <CohesinClamp 
            position={clampPos} 
            rotation={clampRot} 
            active={extrusionState.current.active} 
        />

        {/* Boundary Markers */}
        {BOUNDARIES.map(idx => (
             <Billboard key={`b-${idx}`} position={positions.current[idx] ? [positions.current[idx].x, positions.current[idx].y + 2, positions.current[idx].z] : [0,0,0]}>
                 <Text fontSize={0.3} color="#60a5fa" outlineWidth={0.02} outlineColor="#1e3a8a">CTCF_BOUNDARY</Text>
             </Billboard>
        ))}
    </Group>
  );
};


const PolymerSimulation = ({ adjacency, colorBase }: DNAVisualizerProps) => {
  const positions = useRef<THREE.Vector3[]>([]);
  const velocities = useRef<THREE.Vector3[]>([]);

  // State for Loop Extrusion Process (PNAS 2016)
  // The motor binds, extrudes a loop by pulling feet apart, and falls off at boundaries.
  const extrusionState = useRef({
      active: true,
      center: 6,
      leftFoot: 6,
      rightFoot: 7,
      timer: 0
  });

  // Initialize positions
  useMemo(() => {
    if (positions.current.length === 0) {
      for (let i = 0; i < NUM_PARTICLES; i++) {
        // Initial linear layout with some noise
        positions.current.push(new THREE.Vector3(
          (i - NUM_PARTICLES/2) * 1.5,
          (Math.random() - 0.5) * 2,
          (Math.random() - 0.5) * 2
        ));
        velocities.current.push(new THREE.Vector3(0, 0, 0));
      }
    }
  }, []);

  // Physics Loop
  useFrame(() => {
    const pos = positions.current;
    const vel = velocities.current;

    // --- 1. Loop Extrusion Logic ---
    const ext = extrusionState.current;
    ext.timer++;

    // Slow down the motor steps (every 20 frames)
    if (ext.active && ext.timer > 20) {
        ext.timer = 0;
        let stalled = false;

        // Try to step left
        if (ext.leftFoot > 0 && !BOUNDARIES.includes(ext.leftFoot)) {
             ext.leftFoot--;
        } else {
            stalled = true;
        }

        // Try to step right
        if (ext.rightFoot < NUM_PARTICLES - 1 && !BOUNDARIES.includes(ext.rightFoot)) {
             ext.rightFoot++;
        } else {
            stalled = true;
        }

        // If hit boundaries on both sides or loop is too big, dissociate
        if (stalled || (ext.rightFoot - ext.leftFoot) > 8) {
            ext.active = false;
            ext.timer = -100; // Refractory period
        }
    } else if (!ext.active && ext.timer > 50) {
        // Re-bind at a random location (start a new loop)
        const newStart = Math.floor(Math.random() * (NUM_PARTICLES - 2));
        ext.center = newStart;
        ext.leftFoot = newStart;
        ext.rightFoot = newStart + 1;
        ext.active = true;
        ext.timer = 0;
    }

    // --- 2. Force Accumulation ---
    for (let i = 0; i < NUM_PARTICLES; i++) {
      const force = new THREE.Vector3(0, 0, 0);

      // A. Center Gravity
      force.add(pos[i].clone().multiplyScalar(-0.01));

      // B. Repulsion (Volume exclusion)
      for (let j = 0; j < NUM_PARTICLES; j++) {
        if (i === j) continue;
        const diff = new THREE.Vector3().subVectors(pos[i], pos[j]);
        const dist = diff.length();

        // Hard sphere repulsion
        if (dist < 1.0) {
            force.add(diff.normalize().multiplyScalar(5.0)); // Strong push
        } else if (dist < 4.0) {
            force.add(diff.normalize().multiplyScalar(REPULSION / (dist * dist)));
        }
      }

      // C. Backbone Constraints (Springs)
      const springK = 0.3;
      if (i > 0) {
          const prev = i - 1;
          const diff = new THREE.Vector3().subVectors(pos[prev], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * springK));
      }
      if (i < NUM_PARTICLES - 1) {
          const next = i + 1;
          const diff = new THREE.Vector3().subVectors(pos[next], pos[i]);
          const dist = diff.length();
          const stretch = dist - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * springK));
      }

      // D. MATRIX FORCES (Background Evolution)
      // This gives the "crumpled globule" look
      for (let j = 0; j < NUM_PARTICLES; j++) {
          if (i === j) continue;
          const weight = adjacency[i][j];
          if (weight > 0.1) {
              const diff = new THREE.Vector3().subVectors(pos[j], pos[i]);
              force.add(diff.normalize().multiplyScalar(0.02 * weight));
          }
      }

      // E. EXTRUSION FORCE (The Motor)
      // Strong attraction between the "feet" of the cohesin loop
      if (ext.active) {
          if (i === ext.leftFoot) {
              const target = pos[ext.rightFoot];
              const diff = new THREE.Vector3().subVectors(target, pos[i]);
              force.add(diff.multiplyScalar(0.2)); // Pull towards right foot
          }
          if (i === ext.rightFoot) {
              const target = pos[ext.leftFoot];
              const diff = new THREE.Vector3().subVectors(target, pos[i]);
              force.add(diff.multiplyScalar(0.2)); // Pull towards left foot
          }
          // Push the loop body OUTWARDS so it forms a loop shape visually
          if (i > ext.leftFoot && i < ext.rightFoot) {
             // Find vector away from the feet midpoint
             const mid = new THREE.Vector3().addVectors(pos[ext.leftFoot], pos[ext.rightFoot]).multiplyScalar(0.5);
             const away = new THREE.Vector3().subVectors(pos[i], mid).normalize();
             force.add(away.multiplyScalar(0.1));
          }
      }

      vel[i].add(force);
      vel[i].multiplyScalar(DAMPING); 
    }

    for (let i = 0; i < NUM_PARTICLES; i++) {
      pos[i].add(vel[i]);
    }
  });

  return (
      <ChromatinSpaghetti positions={positions} colorBase={colorBase} extrusionState={extrusionState} />
  );
};

