export enum StrategyType {
  Direct = 'direct',
  Flat = 'flat',
  Hierarchical = 'hierarchical',
  Topological = 'topological',
}

export interface ClusterNode {
  id: string;
  name: string;
  status: 'active' | 'standby' | 'syncing';
  runtime: string; // e.g. "8h 47min"
