const ChromatinSpaghetti = ({ positions, colorBase, extrusionState }: { positions: React.MutableRefObject<THREE.Vector3[]>, colorBase: [number, number, number], extrusionState: React.MutableRefObject<any> }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const spheresRef = useRef<THREE.Group>(null);

  const curve = useMemo(() => new THREE.CatmullRomCurve3(
      new Array(NUM_PARTICLES).fill(0).map(() => new THREE.Vector3()), 
      false, 
      'catmullrom', 
      0.5
  ), []);

  const [clampPos, setClampPos] = useState(new THREE.Vector3(0,0,0));
  const [clampRot, setClampRot] = useState(new THREE.Quaternion());

  useFrame(() => {
    if (!meshRef.current || positions.current.length === 0) return;

    // Update Curve
    for(let i=0; i<NUM_PARTICLES; i++) {
        curve.points[i].copy(positions.current[i]);
    }

    // Geometry Update
    if (meshRef.current.geometry) meshRef.current.geometry.dispose();
    // Thicker tube for visibility
    meshRef.current.geometry = new THREE.TubeGeometry(curve, 300, 0.4, 8, false); 

    // Update Spheres
    if (spheresRef.current) {
        spheresRef.current.children.forEach((child: any, i) => {
            if (positions.current[i]) {
                child.position.copy(positions.current[i]);
                if (BOUNDARIES.includes(i)) {
                    child.scale.setScalar(2.0);
                } else {
                    child.scale.setScalar(1.0);
                }
            }
        });
    }

    // Update Clamp
    const state = extrusionState.current;
    if (state.active) {
        const left = positions.current[state.leftFoot];
        const right = positions.current[state.rightFoot];
        if (left && right) {
            const mid = new THREE.Vector3().addVectors(left, right).multiplyScalar(0.5);
            setClampPos(mid);
            const axis = new THREE.Vector3().subVectors(right, left).normalize();
            const up = new THREE.Vector3(0, 1, 0);
            const q = new THREE.Quaternion().setFromUnitVectors(up, axis);
            const q2 = new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(1,0,0), Math.PI/2);
            q.multiply(q2);
            setClampRot(q);
        }
    }
  });

  return (
    <Group>
        {/* Backbone: Dark Slate to stand out on White */}
        <Mesh ref={meshRef}>
            <MeshStandardMaterial 
                color="#334155" 
                roughness={0.5} 
                metalness={0.1} 
                transparent={true}
                opacity={0.7}
            />
        </Mesh>

        {/* Nucleosomes: Vivid Colors */}
        <Group ref={spheresRef}>
            {new Array(NUM_PARTICLES).fill(0).map((_, i) => {
                const color = getDomainColor(i);
                const isBoundary = BOUNDARIES.includes(i);

                return (
                    <Mesh key={i}>
                        <SphereGeometry args={[0.5, 8, 8]} />
                        <MeshStandardMaterial 
                            color={isBoundary ? '#000000' : color} 
                            emissive={isBoundary ? '#000000' : color}
                            emissiveIntensity={isBoundary ? 0 : 0.2}
                            roughness={0.2}
                        />
                    </Mesh>
                );
            })}
        </Group>

        <CohesinClamp 
            position={clampPos} 
            rotation={clampRot} 
            active={extrusionState.current.active} 
        />

        {BOUNDARIES.map((idx, i) => (
             <Billboard key={`b-${idx}`} position={positions.current[idx] ? [positions.current[idx].x, positions.current[idx].y + 4, positions.current[idx].z] : [0,0,0]}>
                 <Text fontSize={2} color="#000000" fontWeight={900}>CTCF</Text>
             </Billboard>
        ))}
    </Group>
  );
};


const PolymerSimulation = ({ adjacency, colorBase }: DNAVisualizerProps) => {
  const positions = useRef<THREE.Vector3[]>([]);
  const velocities = useRef<THREE.Vector3[]>([]);

  const extrusionState = useRef({
      active: true,
      center: 200,
      leftFoot: 200,
      rightFoot: 201,
      timer: 0
  });

  useMemo(() => {
    if (positions.current.length === 0) {
      // INITIALIZATION: FLAT LINE
      // Start as a long straight line to show folding process
      for (let i = 0; i < NUM_PARTICLES; i++) {
        // Spread 512 particles along X axis
        const x = (i - NUM_PARTICLES / 2) * 1.0; 
        positions.current.push(new THREE.Vector3(x, 0, (Math.random() - 0.5) * 2));
        velocities.current.push(new THREE.Vector3(0, 0, 0));
      }
    }
  }, []);

  useFrame(() => {
    const pos = positions.current;
    const vel = velocities.current;

    // --- 1. Loop Extrusion ---
    const ext = extrusionState.current;
    ext.timer++;

    if (ext.active && ext.timer > 30) { // Faster motor for larger scale
        ext.timer = 0;
        let stalled = false;

        if (ext.leftFoot > 0 && !BOUNDARIES.includes(ext.leftFoot)) ext.leftFoot--;
        else stalled = true;

        if (ext.rightFoot < NUM_PARTICLES - 1 && !BOUNDARIES.includes(ext.rightFoot)) ext.rightFoot++;
        else stalled = true;

        // Larger loop max size
        if (stalled || (ext.rightFoot - ext.leftFoot) > 50) {
            ext.active = false;
            ext.timer = -100; 
        }
    } else if (!ext.active && ext.timer > 100) {
        const newStart = Math.floor(Math.random() * (NUM_PARTICLES - 50));
        ext.center = newStart;
        ext.leftFoot = newStart;
        ext.rightFoot = newStart + 1;
        ext.active = true;
        ext.timer = 0;
    }

    // --- 2. Physics Optimization ---
    for (let i = 0; i < NUM_PARTICLES; i++) {
      const force = new THREE.Vector3(0, 0, 0);

      // A. Center Pull (Weak Gravity to facilitate initial collapse)
      force.add(pos[i].clone().multiplyScalar(-0.005));

      // B. Repulsion (Optimized for 512 particles)
      // Only check neighbors within a sliding window to save CPU
      const windowSize = 40; 
      const start = Math.max(0, i - windowSize);
      const end = Math.min(NUM_PARTICLES, i + windowSize);

      for (let j = start; j < end; j++) {
        if (i === j) continue;
        const diff = new THREE.Vector3().subVectors(pos[i], pos[j]);
        const distSq = diff.lengthSq();

        if (distSq < 0.1) {
             // Emergency push
             force.add(new THREE.Vector3((Math.random()-0.5), (Math.random()-0.5), (Math.random()-0.5)).multiplyScalar(5));
        } else if (distSq < 4.0) {
            const dist = Math.sqrt(distSq);
            force.add(diff.normalize().multiplyScalar(REPULSION / distSq));
        }
      }

      // C. Backbone
      const springK = 0.5;
      if (i > 0) {
          const prev = i - 1;
          const diff = new THREE.Vector3().subVectors(pos[prev], pos[i]);
          const stretch = diff.length() - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * springK));
      }
      if (i < NUM_PARTICLES - 1) {
          const next = i + 1;
          const diff = new THREE.Vector3().subVectors(pos[next], pos[i]);
          const stretch = diff.length() - BACKBONE_LENGTH;
          force.add(diff.normalize().multiplyScalar(stretch * springK));
      }

      // D. MATRIX FORCES (The Folding Driver)
      // This pulls distant parts together based on TADs
      // Only check relevant range to optimize
      const foldWindow = 80;
      const foldStart = Math.max(0, i - foldWindow);
      const foldEnd = Math.min(NUM_PARTICLES, i + foldWindow);

      for (let j = foldStart; j < foldEnd; j++) {
          if (i === j) continue;

          // Only process significant weights
          if (Math.abs(i - j) < 5) continue; // Skip immediate neighbors (handled by backbone)

          const weight = adjacency[i][j];
          if (weight > 0.15) {
              const diff = new THREE.Vector3().subVectors(pos[j], pos[i]);
              // Pull stronger to collapse the flat line
              force.add(diff.normalize().multiplyScalar(0.02 * weight));
          }
      }

      // E. Motor Force
      if (ext.active) {
          const motorStrength = 0.15; 

          if (i === ext.leftFoot) {
              const target = pos[ext.rightFoot];
              const diff = new THREE.Vector3().subVectors(target, pos[i]);
              force.add(diff.multiplyScalar(motorStrength)); 
          }
          if (i === ext.rightFoot) {
              const target = pos[ext.leftFoot];
              const diff = new THREE.Vector3().subVectors(target, pos[i]);
              force.add(diff.multiplyScalar(motorStrength)); 
          }
          if (i > ext.leftFoot && i < ext.rightFoot) {
             const mid = new THREE.Vector3().addVectors(pos[ext.leftFoot], pos[ext.rightFoot]).multiplyScalar(0.5);
             const away = new THREE.Vector3().subVectors(pos[i], mid).normalize();
             force.add(away.multiplyScalar(0.1));
          }
      }

      vel[i].add(force);
      vel[i].multiplyScalar(DAMPING); 
    }

    for (let i = 0; i < NUM_PARTICLES; i++) {
      pos[i].add(vel[i]);
    }
  });

  return (
      <ChromatinSpaghetti positions={positions} colorBase={colorBase} extrusionState={extrusionState} />
  );
};

