// 128 SCALE CONSTANTS
const NUM_PARTICLES = MATRIX_SIZE;
const REPULSION = 1.2; 
const DAMPING = 0.9; 
const BACKBONE_LENGTH = 1.2; 
const BOUNDARIES = [16, 32, 48, 64, 80, 96, 112];

// High Contrast Colors for White Background
const DOMAIN_COLORS = [
  '#dc2626', // Red 600
  '#ea580c', // Orange 600
  '#ca8a04', // Yellow 600
  '#65a30d', // Lime 600
  '#059669', // Emerald 600
  '#0891b2', // Cyan 600
