  { id: 'n5', name: 'vishuddha', status: 'standby', runtime: '0h 00min', generation: 0, cpuUsage: 15, memoryUsage: 4, temperature: 28, gpuUsage: 0, vramUsage: 0, powerDraw: 45, tflops: 0 },
