export const useExperiment = () => {
  const [simulationState, setSimulationState] = useState<SimulationState | null>(null);
  const stateRef = useRef<SimulationState | null>(null);
  const frameIdRef = useRef<number>(0);
  const startTimeRef = useRef<number>(Date.now());
  const lastGenTimeRef = useRef<number>(0);

  // Initialization helper
  const initializeState = useCallback(() => {
    const initialStrategies = Object.values(StrategyType).reduce((acc, type) => {
      const pop = createInitialPopulation(POPULATION_SIZE);
      const adj = generateAdjacency(pop);
      const rawFitness = computeFitness(pop, adj); 
      const mod = computeModularity(adj);

      acc[type] = {
        type,
        population: pop,
        fitness: rawFitness,
        modularity: mod,
        adjacency: adj,
        fitnessHistory: Array(HISTORY_LENGTH).fill(0)
      };
      return acc;
    }, {} as Record<StrategyType, StrategyData>);

    const initialState: SimulationState = {
      id: Math.random().toString(36).substring(7), // Unique Session ID
      generation: 10,
      simulationDelay: 100, // Default to ~10 generations per second
      strategies: initialStrategies,
      cluster: INITIAL_NODES,
      metrics: {
        topoLead: 0,
        modularityScore: 0,
        thesisProgress: 15
      },
      isRunning: true,
      telemetryMode: 'simulated',
      isLocalConnected: false
    };

    stateRef.current = initialState;
    setSimulationState(initialState);
  }, []);

  // Initialize once
  useEffect(() => {
    initializeState();
  }, [initializeState]);

  // Polling for Local Telemetry
  useEffect(() => {
    const pollInterval = setInterval(async () => {
      if (!stateRef.current || stateRef.current.telemetryMode !== 'local') return;

      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 800);

        const response = await fetch(`http://localhost:${TELEMETRY_PORT}/stats`, { 
            signal: controller.signal 
        });
        clearTimeout(timeoutId);

        if (response.ok) {
          const realData = await response.json();
          // Expecting realData to be an array of ClusterNodes or a single object to merge
          // For now, let's assume the local agent sends an array of nodes
          if (Array.isArray(realData)) {
             stateRef.current.cluster = realData;
             stateRef.current.isLocalConnected = true;
          }
        }
      } catch (e) {
        stateRef.current.isLocalConnected = false;
        // Keep existing data but mark disconnected
      }
    }, 1000);

    return () => clearInterval(pollInterval);
  }, []);

  const tick = useCallback(() => {
    if (!stateRef.current || !stateRef.current.isRunning) return;

    // Time throttling logic for variable speed
    const now = Date.now();
    const elapsed = now - lastGenTimeRef.current;

    if (elapsed < stateRef.current.simulationDelay) {
        frameIdRef.current = requestAnimationFrame(tick);
        return;
    }

    lastGenTimeRef.current = now;

    const currentStrategies = stateRef.current.strategies;
    const nextStrategies = {} as Record<StrategyType, StrategyData>;
    let topoFitness = 0;
    let maxOtherFitness = -999;
    let topoModularity = 0;

    // Evolve strategies
    Object.values(StrategyType).forEach(type => {
      const prev = currentStrategies[type];
      const nextPop = evolvePopulation(prev.population, type);
      const nextAdj = generateAdjacency(nextPop);
      const adjustedFitness = computeFitness(nextPop, nextAdj); 
      const nextModularity = computeModularity(nextAdj);
      const nextHistory = [...prev.fitnessHistory, adjustedFitness].slice(-HISTORY_LENGTH);

      nextStrategies[type] = {
        type,
        population: nextPop,
        fitness: adjustedFitness,
        modularity: nextModularity,
        adjacency: nextAdj,
        fitnessHistory: nextHistory
      };

      if (type === StrategyType.Topological) {
        topoFitness = adjustedFitness;
        topoModularity = nextModularity;
      } else {
        maxOtherFitness = Math.max(maxOtherFitness, adjustedFitness);
      }
    });

    const topoLead = topoFitness - maxOtherFitness;
    const impulse = (topoLead * 20) + (topoModularity * 2); 
    const thesisProgress = Math.min(100, Math.max(0, 
      stateRef.current.metrics.thesisProgress * 0.99 + impulse
    ));

    // Update Cluster Telemetry
    let nextCluster = stateRef.current.cluster;

    if (stateRef.current.telemetryMode === 'simulated') {
        const time = (Date.now() - startTimeRef.current) / 1000;
        nextCluster = stateRef.current.cluster.map((node, i) => {
            const phase = i * (Math.PI / 2);
            const thermalCycle = Math.sin(time * 0.5 + phase) * 2; 
            const jitter = (Math.random() - 0.5) * 1.5;

            let newGen = node.generation;
            if (node.name === 'muladhara') {
                newGen += 1;
            } else if (Math.random() > 0.8) {
                newGen += 1; 
            }

            let status = node.status;
            if (newGen > 0 && status === 'syncing') status = 'active';
            const baseTemp = node.name === 'muladhara' ? 62 : 45;

            // Simulation logic for new metrics
            const isActive = status === 'active';
            const loadFactor = isActive ? 1.0 : 0.1;
            const targetTflops = isActive ? (node.name === 'muladhara' ? 125 : 80) : 0;
            const targetGpu = isActive ? (node.name === 'muladhara' ? 95 : 60) : 0;
            const targetPower = isActive ? (node.name === 'muladhara' ? 450 : 300) : 50;

            return {
                ...node,
                cpuUsage: Math.max(5, Math.min(100, Math.round(node.cpuUsage + (Math.random() - 0.5) * 10))),
                memoryUsage: Math.max(1, parseFloat((node.memoryUsage + (Math.random() - 0.5) * 0.1).toFixed(1))),
                temperature: Math.round(baseTemp + thermalCycle + jitter),
                generation: newGen,
                gpuUsage: Math.max(0, Math.min(100, Math.round(targetGpu + (Math.random() - 0.5) * 5))),
                vramUsage: parseFloat((node.vramUsage * 0.99 + (isActive ? 20 : 2) * 0.01).toFixed(1)),
                powerDraw: Math.round(node.powerDraw * 0.9 + targetPower * 0.1 + (Math.random() - 0.5) * 10),
                tflops: Math.round(node.tflops * 0.9 + targetTflops * 0.1)
            };
        });
    }

    const nextState: SimulationState = {
      id: stateRef.current.id,
      generation: stateRef.current.generation + 1,
      simulationDelay: stateRef.current.simulationDelay,
      strategies: nextStrategies,
      cluster: nextCluster,
      metrics: {
        topoLead,
        modularityScore: topoModularity,
        thesisProgress
      },
      isRunning: stateRef.current.isRunning,
      telemetryMode: stateRef.current.telemetryMode,
      isLocalConnected: stateRef.current.isLocalConnected
    };

    stateRef.current = nextState;
    setSimulationState(nextState);
    frameIdRef.current = requestAnimationFrame(tick);
  }, []);

  useEffect(() => {
    if (stateRef.current?.isRunning) {
        frameIdRef.current = requestAnimationFrame(tick);
    }
    return () => cancelAnimationFrame(frameIdRef.current);
  }, [tick, simulationState?.isRunning]);

  const togglePause = () => {
    if (stateRef.current) {
        stateRef.current.isRunning = !stateRef.current.isRunning;
        setSimulationState({...stateRef.current});
    }
  };

  const resetExperiment = () => {
      initializeState();
  };

  const setTelemetryMode = (mode: 'simulated' | 'local') => {
      if (stateRef.current) {
          stateRef.current.telemetryMode = mode;
          setSimulationState({...stateRef.current});
      }
  };

  const setSimulationDelay = (delay: number) => {
    if (stateRef.current) {
        stateRef.current.simulationDelay = delay;
        setSimulationState({...stateRef.current});
    }
  };

  return { state: simulationState, togglePause, resetExperiment, setTelemetryMode, setSimulationDelay };
};

import React, { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Billboard, Text, Torus, Sphere } from '@react-three/drei';
import * as THREE from 'three';
import { MATRIX_SIZE } from '../types';
import { Play, Pause, Settings2, RotateCw, Droplets, Gauge, Maximize } from 'lucide-react';

// Standard Three.js elements
const Group = 'group' as any;
const Fog = 'fog' as any;
const AmbientLight = 'ambientLight' as any;
const PointLight = 'pointLight' as any;
const DirectionalLight = 'directionalLight' as any;
const Mesh = 'mesh' as any;
const TorusGeometry = 'torusGeometry' as any;
const MeshStandardMaterial = 'meshStandardMaterial' as any;
const GridHelper = 'gridHelper' as any;
const SphereGeometry = 'sphereGeometry' as any;

interface DNAVisualizerProps {
  adjacency: number[][];
  colorBase: [number, number, number];
}

interface SimulationProps extends DNAVisualizerProps {
  paused: boolean;
  speed: number;
  nodeSize: number;
}

// 128 SCALE CONSTANTS
const NUM_PARTICLES = MATRIX_SIZE;
// Physics Constants Tuned for Stability
const REPULSION = 1.2; 
const DAMPING = 0.85; // Higher drag to prevent explosion
const BACKBONE_LENGTH = 1.0; 
const BOUNDARIES = [16, 32, 48, 64, 80, 96, 112];
const MAX_VELOCITY = 1.0; // Strict velocity cap
const BOUNDARY_RADIUS = 50; // Hard boundary radius

// High Contrast Colors for White Background
const DOMAIN_COLORS = [
  '#dc2626', // Red 600
  '#ea580c', // Orange 600
  '#ca8a04', // Yellow 600
  '#65a30d', // Lime 600
  '#059669', // Emerald 600
  '#0891b2', // Cyan 600
  '#2563eb', // Blue 600
  '#7c3aed', // Violet 600
  '#c026d3', // Fuchsia 600
];

const getDomainColor = (index: number) => {
    // 16 unit domains
    const domainIdx = Math.floor(index / 16);
    return DOMAIN_COLORS[domainIdx % DOMAIN_COLORS.length];
};

// Reusable scratch vectors
const scratch = {
    vec: new THREE.Vector3(),
    diff: new THREE.Vector3(),
    force: new THREE.Vector3(),
    mid: new THREE.Vector3(),
    axis: new THREE.Vector3(),
    up: new THREE.Vector3(0, 1, 0),
    dummyRot: new THREE.Quaternion(),
    dummyRot2: new THREE.Quaternion()
};

const CohesinClamp = ({ position, rotation, active }: { position: THREE.Vector3, rotation: THREE.Quaternion, active: boolean }) => {
  return (
    <Group position={position} quaternion={rotation} visible={active}>
       {/* Ring is Dark Gray/Black for high contrast on white */}
       <Mesh rotation={[Math.PI / 2, 0, 0]}>
          <TorusGeometry args={[2.0, 0.4, 16, 32]} />
          <MeshStandardMaterial color="#1e293b" roughness={0.2} metalness={0.8} />
       </Mesh>

       {/* Pink accent light */}
       <PointLight color="#ec4899" intensity={active ? 3 : 0} distance={15} decay={2} />

       <Billboard position={[0, 3.0, 0]}>
          <Text fontSize={1.2} color="#0f172a" outlineWidth={0.0} fontWeight={800}>
             COHESIN
          </Text>
       </Billboard>
    </Group>
  );
};

const ChromatinSpaghetti = ({ 
  positions, 
  colorBase, 
  extrusionState,
  nodeSize
}: { 
  positions: React.MutableRefObject<THREE.Vector3[]>, 
  colorBase: [number, number, number], 
  extrusionState: React.MutableRefObject<any>,
  nodeSize: number
}) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const spheresRef = useRef<THREE.Group>(null);

  const curve = useMemo(() => new THREE.CatmullRomCurve3(
      new Array(NUM_PARTICLES).fill(0).map(() => new THREE.Vector3()), 
      false, 
      'catmullrom', 
      0.5
  ), []);

  const [clampPos, setClampPos] = useState(new THREE.Vector3(0,0,0));
  const [clampRot, setClampRot] = useState(new THREE.Quaternion());

  useFrame(() => {
    if (!meshRef.current || positions.current.length === 0) return;

    // Update Curve
    for(let i=0; i<NUM_PARTICLES; i++) {
        curve.points[i].copy(positions.current[i]);
    }

    // Geometry Update - Backbone thickness scales with nodeSize for consistency
    if (meshRef.current.geometry) meshRef.current.geometry.dispose();
    const tubeRadius = 0.5 * Math.min(1.2, Math.max(0.3, nodeSize));
    meshRef.current.geometry = new THREE.TubeGeometry(curve, 128, tubeRadius, 8, false); 

    // Update Spheres
    if (spheresRef.current) {
        spheresRef.current.children.forEach((child: any, i) => {
            if (positions.current[i]) {
                child.position.copy(positions.current[i]);
                const isBoundary = BOUNDARIES.includes(i);
                // Apply dynamic scaling
                const scale = isBoundary ? 1.5 * nodeSize : 1.0 * nodeSize;
                child.scale.setScalar(scale);
            }
        });
    }

    // Update Clamp
    const state = extrusionState.current;
    if (state.active) {
        const left = positions.current[state.leftFoot];
        const right = positions.current[state.rightFoot];
        if (left && right) {
            scratch.mid.addVectors(left, right).multiplyScalar(0.5);
            setClampPos(scratch.mid.clone()); 

            scratch.axis.subVectors(right, left).normalize();
            scratch.dummyRot.setFromUnitVectors(scratch.up, scratch.axis);
            scratch.dummyRot2.setFromAxisAngle(new THREE.Vector3(1,0,0), Math.PI/2);
            scratch.dummyRot.multiply(scratch.dummyRot2);
            setClampRot(scratch.dummyRot.clone());
        }
    }
  });

  return (
    <Group>
        {/* Backbone */}
        <Mesh ref={meshRef}>
            <MeshStandardMaterial 
                color="#475569" 
                roughness={0.5} 
                metalness={0.1} 
                transparent={true}
                opacity={0.8}
            />
        </Mesh>

        {/* Nucleosomes */}
        <Group ref={spheresRef}>
            {new Array(NUM_PARTICLES).fill(0).map((_, i) => {
                const color = getDomainColor(i);
                const isBoundary = BOUNDARIES.includes(i);

                return (
                    <Mesh key={i}>
                        <SphereGeometry args={[0.6, 8, 8]} />
                        <MeshStandardMaterial 
                            color={isBoundary ? '#000000' : color} 
                            emissive={isBoundary ? '#000000' : color}
                            emissiveIntensity={isBoundary ? 0 : 0.2}
                            roughness={0.2}
                        />
                    </Mesh>
                );
            })}
        </Group>

        <CohesinClamp 
            position={clampPos} 
            rotation={clampRot} 
            active={extrusionState.current.active} 
        />

        {BOUNDARIES.map((idx, i) => (
             <Billboard key={`b-${idx}`} position={positions.current[idx] ? [positions.current[idx].x, positions.current[idx].y + 3, positions.current[idx].z] : [0,0,0]}>
                 <Text fontSize={1.2} color="#000000" fontWeight={900}>CTCF</Text>
             </Billboard>
        ))}
    </Group>
  );
};


const PolymerSimulation = ({ adjacency, colorBase, paused, speed, nodeSize }: SimulationProps) => {
  const positions = useRef<THREE.Vector3[]>([]);
  const velocities = useRef<THREE.Vector3[]>([]);

  const extrusionState = useRef({
      active: true,
      center: 64,
      leftFoot: 64,
      rightFoot: 65,
      timer: 0
  });

  useMemo(() => {
    if (positions.current.length === 0) {
      // INITIALIZATION
      for (let i = 0; i < NUM_PARTICLES; i++) {
        const x = (i - NUM_PARTICLES / 2) * 1.5; 
        positions.current.push(new THREE.Vector3(x, Math.sin(i * 0.1) * 2, (Math.random() - 0.5) * 1));
        velocities.current.push(new THREE.Vector3(0, 0, 0));
      }
    }
  }, []);

  useFrame(() => {
    if (paused) return; // Freezes physics and logic

    const pos = positions.current;
    const vel = velocities.current;

    // --- 1. Loop Extrusion Logic ---
    const ext = extrusionState.current;

    // Speed directly affects how fast the motor steps occur
    ext.timer += speed; 

    // Threshold is constant (5 frames at 1x speed). 
    // Higher speed = reach threshold faster = faster extrusion.
    if (ext.active && ext.timer > 5) { 
        ext.timer = 0;
        let stalled = false;

        if (ext.leftFoot > 0 && !BOUNDARIES.includes(ext.leftFoot)) ext.leftFoot--;
        else stalled = true;

        if (ext.rightFoot < NUM_PARTICLES - 1 && !BOUNDARIES.includes(ext.rightFoot)) ext.rightFoot++;
        else stalled = true;

        if (stalled || (ext.rightFoot - ext.leftFoot) > 32) {
            ext.active = false;
            ext.timer = -200; // Pause before reset
        }
    } else if (!ext.active && ext.timer > 200) {
        // Reset
        const newStart = Math.floor(Math.random() * (NUM_PARTICLES - 20));
        ext.center = newStart;
        ext.leftFoot = newStart;
        ext.rightFoot = newStart + 1;
        ext.active = true;
        ext.timer = 0;
    }

    // --- 2. Physics Engine ---
    for (let i = 0; i < NUM_PARTICLES; i++) {
      scratch.force.set(0, 0, 0);

      // A. Center Pull (STRONG - Prevents drift)
      scratch.vec.copy(pos[i]).multiplyScalar(-0.02); 
      scratch.force.add(scratch.vec);

      // B. Repulsion
      const windowSize = 25; 
      const start = Math.max(0, i - windowSize);
      const end = Math.min(NUM_PARTICLES, i + windowSize);

      for (let j = start; j < end; j++) {
        if (i === j) continue;
        scratch.diff.subVectors(pos[i], pos[j]);
        const distSq = scratch.diff.lengthSq();

        if (distSq < 0.1) {
             // Avoid singularity
             scratch.vec.set((Math.random()-0.5), (Math.random()-0.5), (Math.random()-0.5)).multiplyScalar(0.5);
             scratch.force.add(scratch.vec);
        } else if (distSq < 8.0) {
            // Soft inverse square force with HARD CAP
            let f = REPULSION / (distSq + 0.1);
            if (f > 2.0) f = 2.0; // Cap repulsion force to prevent explosions
            scratch.diff.multiplyScalar(f); 
            scratch.force.add(scratch.diff);
        }
      }

      // C. Backbone Constraints
      const springK = 0.5;
      if (i > 0) {
          scratch.diff.subVectors(pos[i-1], pos[i]);
          const len = scratch.diff.length();
          const stretch = len - BACKBONE_LENGTH;
          scratch.diff.normalize().multiplyScalar(stretch * springK);
          scratch.force.add(scratch.diff);
      }
      if (i < NUM_PARTICLES - 1) {
          scratch.diff.subVectors(pos[i+1], pos[i]);
          const len = scratch.diff.length();
          const stretch = len - BACKBONE_LENGTH;
          scratch.diff.normalize().multiplyScalar(stretch * springK);
          scratch.force.add(scratch.diff);
      }

      // D. MATRIX FORCES (Global Folding)
      const foldWindow = 40; 
      const foldStart = Math.max(0, i - foldWindow);
      const foldEnd = Math.min(NUM_PARTICLES, i + foldWindow);

      for (let j = foldStart; j < foldEnd; j++) {
          if (i === j) continue;
          if (Math.abs(i - j) < 4) continue; 

          const weight = adjacency[i][j];
          if (weight > 0.15) {
              scratch.diff.subVectors(pos[j], pos[i]);
              scratch.diff.normalize().multiplyScalar(0.02 * weight);
              scratch.force.add(scratch.diff);
          }
      }

      // E. Motor Force
      if (ext.active) {
          const motorStrength = 0.05; 

          if (i === ext.leftFoot) {
              scratch.diff.subVectors(pos[ext.rightFoot], pos[i]);
              scratch.force.add(scratch.diff.multiplyScalar(motorStrength)); 
          }
          if (i === ext.rightFoot) {
              scratch.diff.subVectors(pos[ext.leftFoot], pos[i]);
              scratch.force.add(scratch.diff.multiplyScalar(motorStrength)); 
          }
          if (i > ext.leftFoot && i < ext.rightFoot) {
             scratch.mid.addVectors(pos[ext.leftFoot], pos[ext.rightFoot]).multiplyScalar(0.5);
             scratch.diff.subVectors(pos[i], scratch.mid).normalize().multiplyScalar(0.03);
             scratch.force.add(scratch.diff);
          }
      }

      // --- INTEGRATION ---
      // Apply forces
      vel[i].add(scratch.force.multiplyScalar(speed * 0.5)); // Reduced timestep for stability

      // Damping (Higher Friction)
      vel[i].multiplyScalar(DAMPING); 

      // Strict Velocity Clamp
      const vSq = vel[i].lengthSq();
      if (vSq > MAX_VELOCITY * MAX_VELOCITY) {
          vel[i].multiplyScalar(MAX_VELOCITY / Math.sqrt(vSq));
      }

      // Position Update
      scratch.vec.copy(vel[i]).multiplyScalar(speed);
      pos[i].add(scratch.vec);

      // Boundary Constraint (Spherical Container)
      const rSq = pos[i].lengthSq();
      if (rSq > BOUNDARY_RADIUS * BOUNDARY_RADIUS) {
          const r = Math.sqrt(rSq);
          // Strong elastic push back
          scratch.vec.copy(pos[i]).normalize().multiplyScalar(-1.0); 
          vel[i].add(scratch.vec); // Reverse velocity

          // Hard clamp position
          pos[i].normalize().multiplyScalar(BOUNDARY_RADIUS);
      }
    }
  });

  return (
      <ChromatinSpaghetti 
        positions={positions} 
        colorBase={colorBase} 
        extrusionState={extrusionState} 
        nodeSize={nodeSize} 
      />
  );
};

