    { label: 'AQUATIC', sub: 'Devonian Period' },
    { label: 'AMPHIBIAN', sub: 'Carboniferous Period' },
    { label: 'PRIMATE', sub: 'Paleogene Period' },
    { label: 'SAPIENS', sub: 'Anthropocene' },
  ];

  return (
    <div className="flex items-center gap-3 bg-slate-900/50 px-4 py-2 rounded-lg border border-slate-800/50">
