        <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round" className="transition-all duration-300">
           {stage === 0 && (
             <g>
               <path d="M6.5 12c.5-2.5 2.5-4.5 5-4.5 3.5 0 6 2.5 6 5.5s-2.5 5.5-6 5.5c-2.5 0-4.5-2-5-4.5" />
