               <path d="M2 12l4.5-4v8z" />
               <circle cx="14" cy="10.5" r="1" fill="currentColor" />
             </g>
           )}
           {stage === 1 && (
             <g>
                <path d="M12 16c2-1 4-1 6 0" />
                <path d="M8 14l-2 2" /> 
                <path d="M16 14l2 2" />
                <path d="M10 10c0-3 1-5 4-5 2 0 3 2 3 4" />
                <path d="M7 15c-1 1-3 1-4 0" />
                <circle cx="14" cy="8" r="0.5" fill="currentColor" />
             </g>
           )}
           {stage === 2 && (
             <g>
                <circle cx="12" cy="7" r="3" />
                <path d="M12 10c-2 2-2 6-1 9" />
                <path d="M11 19l-3 3" />
                <path d="M12 13l-4 2" />
                <path d="M12 13l4-3" />
                <path d="M15 10c2-1 4 0 4 3 0 2-2 3-4 3" />
             </g>
           )}
           {stage === 3 && (
             <g>
               <circle cx="12" cy="5" r="2" />
               <path d="M12 7v7" />
               <path d="M9 10l3-2 3 2" />
               <path d="M12 14l-2 8" />
               <path d="M12 14l2 8" />
             </g>
           )}
        </svg>
      </div>

      <div className="flex flex-col">
         <span className="text-[10px] text-slate-500 font-mono leading-tight">{stages[stage].label}</span>
         <span className="text-xl font-bold text-slate-100 leading-none font-mono tracking-tight">
            GEN {generation.toString().padStart(5, '0')}
         </span>
         <div className="h-0.5 w-full bg-slate-800 mt-1 overflow-hidden rounded-full">
             <div 
               className="h-full bg-indigo-500 transition-all duration-100" 
               style={{ width: `${(generation % 100)}%` }}
             />
         </div>
      </div>
    </div>
  );
};

