// Data derived from "Genomic-Inspired Weight Compression for Neuroevolution" (Nevin)
// Benchmark: Ant Locomotion (Round 1)
// Key Insight: "Variance Collapse" - Structured encodings have low variance but lower peak fitness.

export interface DataPoint {
  gen: number;
  direct: number;
  flat: number;
  hierarchical: number;
  topological: number;
  modularity: number;
}

const TOTAL_FRAMES = 101;

export const EXPERIMENTAL_DATASET: DataPoint[] = Array.from({ length: TOTAL_FRAMES }).map((_, i) => {
  const progress = i / (TOTAL_FRAMES - 1);

  // Logistic growth helper
  // t: time 0-1, k: steepness, x0: midpoint
  const sigmoid = (t: number, k: number, x0: number) => 1 / (1 + Math.exp(-k * (t - x0)));

  // 1. FLAT (The Winner)
  // From JSON: Mean ~407.9, Std ~52.7
  // Behavior: High peak, high variance (noisy learning curve)
  const flatBase = 407.9 * sigmoid(progress, 12, 0.15);
  // Variance increases as fitness grows
  const flatNoise = (Math.random() - 0.5) * (52.7 * Math.min(1, progress * 1.5)); 
  const flat = Math.max(0, flatBase + flatNoise);

  // 2. HIERARCHICAL (TAD-like)
  // From JSON: Mean ~378.2, Std ~30.8
  // Behavior: Lower peak, moderate variance
  const hierBase = 378.2 * sigmoid(progress, 10, 0.2);
  const hierNoise = (Math.random() - 0.5) * (30.8 * Math.min(1, progress * 1.5));
  const hierarchical = Math.max(0, hierBase + hierNoise);

  // 3. TOPOLOGICAL (Chromatin-like)
  // From JSON: Mean ~366.4, Std ~12.3
  // Behavior: "Variance Collapse" - Very smooth line, consistent, but suboptimal peak.
  // It gets stuck in a "Discrete Landscape Basin".
  const topoBase = 366.4 * sigmoid(progress, 9, 0.2);
  const topoNoise = (Math.random() - 0.5) * (12.3 * Math.min(1, progress * 1.5)); // Very low noise
  const topological = Math.max(0, topoBase + topoNoise);

  // 4. DIRECT (Control/Random)
  // Used as a low-end baseline for visualization context
  const direct = 150 * sigmoid(progress, 5, 0.4) + (Math.random() - 0.5) * 40;

  // Modularity Score (Q)
  // Crucial Insight: Topological encoding FORCES high modularity (structure), even if fitness is lower.
  // This explains the "Landscape Surgery" - we successfully created structure (TADs), 
  // but that structure constrained the solution space too much.
  const modularity = 0.65 + (0.25 * sigmoid(progress, 5, 0.1)) + (Math.random() * 0.02);

  return {
    gen: i,
    direct,
    flat,
    hierarchical,
    topological,
    modularity
  };
});

