export enum StrategyType {
  Direct = 'direct',
  Flat = 'flat',
  Hierarchical = 'hierarchical',
  Topological = 'topological',
}

export interface ClusterNode {
  id: string;
  name: string;
  status: 'active' | 'standby' | 'syncing';
  runtime: string; // e.g. "8h 47min"
  generation: number;
  cpuUsage: number; // %
  memoryUsage: number; // GB
  temperature: number; // Celsius
  gpuUsage: number; // %
  vramUsage: number; // GB
  powerDraw: number; // Watts
  tflops: number; // TeraFLOPS
}

export interface SimulationState {
  id: string; // Session ID for Reset handling
  generation: number;
  simulationDelay: number; // ms between generations (0 = max speed)
  strategies: {
    [key in StrategyType]: StrategyData;
  };
  cluster: ClusterNode[];
  metrics: {
    topoLead: number;
    modularityScore: number;
    thesisProgress: number;
  };
  isRunning: boolean;
  telemetryMode: 'simulated' | 'local';
  isLocalConnected: boolean;
  playbackMode: 'theory' | 'experimental'; // NEW: Toggle between Live Sim and Data Replay
}

export interface StrategyData {
  type: StrategyType;
  population: number[];
  fitness: number;
  modularity: number;
  adjacency: number[][];
  fitnessHistory: number[]; // For time-series chart
  variance: number; // Current standard deviation
  varianceHistory: number[]; // For variance collapse chart
}

// Optimized Resolution for Mechanical Clarity
export const MATRIX_SIZE = 128; 
export const POPULATION_SIZE = 16384; // 128 * 128

// Data derived from "Genomic-Inspired Weight Compression for Neuroevolution" (Nevin)
// Benchmark: Ant Locomotion (Round 1)
// Key Insight: "Variance Collapse" - Structured encodings have low variance but lower peak fitness.

export interface DataPoint {
  gen: number;
  direct: number;
  flat: number;
  hierarchical: number;
  topological: number;
  modularity: number;

  // Standard Deviations (Variance)
  flatStd: number;
  hierStd: number;
  topoStd: number;
  directStd: number;
}

const TOTAL_FRAMES = 101;

export const EXPERIMENTAL_DATASET: DataPoint[] = Array.from({ length: TOTAL_FRAMES }).map((_, i) => {
  const progress = i / (TOTAL_FRAMES - 1);

  // Logistic growth helper
  // t: time 0-1, k: steepness, x0: midpoint
  const sigmoid = (t: number, k: number, x0: number) => 1 / (1 + Math.exp(-k * (t - x0)));

  // 1. FLAT (The Winner)
  // Mean ~407.9, Std ~52.7
  const flatBase = 407.9 * sigmoid(progress, 12, 0.15);
  const flatStd = 52.7 * Math.min(1, 0.2 + progress * 0.8); // Variance grows with fitness
  const flatNoise = (Math.random() - 0.5) * flatStd; 
  const flat = Math.max(0, flatBase + flatNoise);

  // 2. HIERARCHICAL (TAD-like)
  // Mean ~378.2, Std ~30.8
  const hierBase = 378.2 * sigmoid(progress, 10, 0.2);
  const hierStd = 30.8 * Math.max(0.2, 1.0 - progress * 0.3); // Variance reduces slightly
  const hierNoise = (Math.random() - 0.5) * hierStd;
  const hierarchical = Math.max(0, hierBase + hierNoise);

  // 3. TOPOLOGICAL (Chromatin-like)
  // Mean ~366.4, Std ~12.3
  // "Variance Collapse": Std starts moderate and collapses to very low
  const topoBase = 366.4 * sigmoid(progress, 9, 0.2);
  const topoStd = 25.0 * Math.max(0.1, Math.exp(-progress * 3)); // Rapid collapse
  const topoNoise = (Math.random() - 0.5) * (12.3 * Math.min(1, progress * 1.5)); 
  const topological = Math.max(0, topoBase + topoNoise);

  // 4. DIRECT (Control/Random)
  const direct = 150 * sigmoid(progress, 5, 0.4) + (Math.random() - 0.5) * 40;
  const directStd = 40;

  // Modularity Score (Q)
  const modularity = 0.65 + (0.25 * sigmoid(progress, 5, 0.1)) + (Math.random() * 0.02);

  return {
    gen: i,
    direct,
    flat,
    hierarchical,
    topological,
    modularity,
    flatStd,
    hierStd,
    topoStd,
    directStd
  };
});

import { StrategyType, MATRIX_SIZE } from '../types';

export function createInitialPopulation(size: number): number[] {
  // We utilize a 1:1 mapping between population genes and matrix cells
  return Array(size).fill(0).map(() => Math.random() * 2 - 1);
}

// NEW: Calculate the energy cost of the structure
// DNA creates "Topologically Associating Domains" (TADs) to minimize the wire-length between interacting genes.
// Random structures have high wire-length -> High Metabolic Cost -> Extinction.
export function computeMetabolicCost(adj: number[][]): number {
  const n = adj.length;
  let totalCost = 0;
  let totalSignal = 0;

  // Optimization: Sample the matrix for cost calculation
  const step = 2; 

  for (let i = 0; i < n; i += step) {
    for (let j = 0; j < n; j += step) {
      const weight = adj[i][j];
      if (weight > 0.05) {
        const dist = Math.abs(i - j);
        totalCost += weight * (dist * dist);
        totalSignal += weight;
      }
    }
  }

  // Normalized cost per unit of signal
  return totalSignal > 0 ? (totalCost / totalSignal) / (n * n) : 0;
}

export function computeFitness(pop: number[], adj: number[][]): number {
  if (pop.length === 0) return 0;

  // 1. Raw Vitality (Signal Strength)
  let sum = 0;
  let sumSq = 0;
  const sampleSize = Math.min(pop.length, 1000);
  for(let k=0; k<sampleSize; k++) {
      const val = pop[Math.floor(Math.random() * pop.length)];
      sum += val;
      sumSq += (val * val);
  }

  const mean = sum / sampleSize;
  const variance = (sumSq / sampleSize) - (mean * mean);
  const vitality = (mean * 0.5 + Math.sqrt(Math.max(0, variance)) * 0.5);

  // 2. Metabolic Cost (The Entropy Tax)
  const cost = computeMetabolicCost(adj);

  // 3. Efficiency Ratio
  return vitality - (cost * 2.5); 
}

export function generateAdjacency(pop: number[]): number[][] {
  const n = MATRIX_SIZE;
  const adj = Array(n).fill(0).map(() => Array(n).fill(0));

  for (let i = 0; i < n * n; i++) {
    const row = Math.floor(i / n);
    const col = i % n;
    const geneVal = pop[i % pop.length];
    adj[row][col] = Math.max(0, geneVal);
  }

  const rowSums = adj.map(row => row.reduce((a, b) => a + b, 0));
  for (let i = 0; i < n; i++) {
    if (rowSums[i] > 0.001) {
      for (let j = 0; j < n; j++) {
        adj[i][j] = adj[i][j] / (rowSums[i] * 0.8 + 0.2); 
      }
    }
  }
  return adj;
}

// NEW: Generates a synthetic adjacency matrix based purely on a target Modularity Score.
// Used for "Experimental Playback" mode to visualize the data without running the full physics engine.
export function generateSyntheticAdjacency(modularityTarget: number): number[][] {
    const n = MATRIX_SIZE;
    const TAD_SIZE = 16;
    const adj = Array(n).fill(0).map(() => Array(n).fill(0));

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            const rowTad = Math.floor(i / TAD_SIZE);
            const colTad = Math.floor(j / TAD_SIZE);
            const dist = Math.abs(i - j);

            let val = 0;

            if (rowTad === colTad) {
                // Inside TAD
                // Strength correlates with modularityTarget
                val = modularityTarget * 0.8; 

                // Decay
                if (dist < 8) val += (1 - dist/8) * 0.2;

                // Corner Peaks
                const tadStart = rowTad * TAD_SIZE;
                const tadEnd = tadStart + TAD_SIZE;
                const isCorner = (i < tadStart + 3 && j > tadEnd - 4) || (j < tadStart + 3 && i > tadEnd - 4);
                if (isCorner) val += modularityTarget * 0.5;

            } else {
                // Noise floor
                val = Math.random() * 0.05;
            }

            // Ensure visual contrast
            adj[i][j] = Math.max(0, Math.min(1, val));
        }
    }
    return adj;
}

export function computeModularity(adj: number[][]): number {
  const n = adj.length;
  let score = 0;
  let totalWeight = 0;
  const step = 2; 

  for (let i = 0; i < n; i += step) {
    for (let j = 0; j < n; j += step) {
      const weight = adj[i][j];
      totalWeight += weight;
      const dist = Math.abs(i - j);

      if (dist <= 4) { 
        score += weight * (5 - dist); 
      } else {
        score -= weight * (dist * 0.2); 
      }
    }
  }

  return totalWeight > 0 ? Math.max(0, score / totalWeight) : 0;
}

export function computeHistoryVariance(history: number[]): number {
    if (history.length < 2) return 0;
    const mean = history.reduce((a, b) => a + b, 0) / history.length;
    const sqDiff = history.reduce((a, b) => a + Math.pow(b - mean, 2), 0);
    return Math.sqrt(sqDiff / history.length);
}

export function evolvePopulation(pop: number[], strategy: StrategyType): number[] {
  const nextPop = [...pop];
  const n = MATRIX_SIZE;

  // Define fixed CTCF Boundary Sites for 128-mer (Every 16 units)
  const TAD_SIZE = 16;

  for (let i = 0; i < nextPop.length; i++) {
    let gene = nextPop[i];

    // Thermal Noise (Entropy)
    gene += (Math.random() - 0.5) * 0.2;

    const row = Math.floor(i / n);
    const col = i % n;

    // Euclidean distance from diagonal (interaction distance)
    const dist = Math.abs(row - col);

    if (strategy === StrategyType.Topological) {
      // LOGIC: Create squares along the diagonal (TADs)
      const rowTad = Math.floor(row / TAD_SIZE);
      const colTad = Math.floor(col / TAD_SIZE);

      if (rowTad === colTad) {
          // 1. We are INSIDE a TAD Square
          // Base interaction probability is high
          gene += 0.2;

          // 2. Diagonal Decay (Polymer Physics)
          if (dist < 8) {
             gene += 0.3 * (1 - dist/8); 
          }

          // 3. Corner Peaks (The "Loop Spot")
          // This creates the distinctive dots seen in Hi-C maps where Cohesin stops
          const tadStart = rowTad * TAD_SIZE;
          const tadEnd = tadStart + TAD_SIZE;

          const isCorner = (row < tadStart + 3 && col > tadEnd - 4) || (col < tadStart + 3 && row > tadEnd - 4);

          if (isCorner) {
              gene += 0.8; // Bright spot at the corner of the TAD
          }

      } else {
          // We are in the empty space between TADs (Insulation)
          gene -= 0.1; 
      }

      // Cleanup noise
      if (gene < 0.1) gene = 0;

    } else if (strategy === StrategyType.Hierarchical) {
       // Fractal pattern
       const levels = 4;
       const target = Math.round(gene * levels) / levels;
       gene = gene + (target - gene) * 0.15;

    } else if (strategy === StrategyType.Flat) {
       // Clamping
       gene = gene * 0.9 + (Math.random() - 0.5) * 0.05;
       gene = Math.max(-0.2, Math.min(0.2, gene));
    } else {
       // Direct / Random Strategy
       if (Math.random() < 0.005) gene = 1;
    }

    nextPop[i] = Math.max(-1, Math.min(1, gene));
  }

  return nextPop;
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { StrategyType, SimulationState, StrategyData, POPULATION_SIZE, ClusterNode } from '../types';
import { createInitialPopulation, evolvePopulation, generateAdjacency, computeFitness, computeModularity, generateSyntheticAdjacency, computeHistoryVariance } from '../utils/simulation';
import { EXPERIMENTAL_DATASET } from '../utils/experimentalData';

const HISTORY_LENGTH = 50;
const TELEMETRY_PORT = 3333;

const INITIAL_NODES: ClusterNode[] = [
  { id: 'n1', name: 'muladhara', status: 'active', runtime: '8h 47min', generation: 10, cpuUsage: 83, memoryUsage: 16, temperature: 62, gpuUsage: 94, vramUsage: 22, powerDraw: 450, tflops: 125 },
  { id: 'n2', name: 'svadhisthana', status: 'syncing', runtime: '4h 51min', generation: 0, cpuUsage: 45, memoryUsage: 12, temperature: 45, gpuUsage: 10, vramUsage: 4, powerDraw: 120, tflops: 0 },
  { id: 'n3', name: 'manipura', status: 'syncing', runtime: '4h 54min', generation: 0, cpuUsage: 56, memoryUsage: 14, temperature: 48, gpuUsage: 12, vramUsage: 4, powerDraw: 135, tflops: 0 },
  { id: 'n4', name: 'anahata', status: 'syncing', runtime: '4h 52min', generation: 0, cpuUsage: 42, memoryUsage: 11, temperature: 42, gpuUsage: 5, vramUsage: 2, powerDraw: 110, tflops: 0 },
  { id: 'n5', name: 'vishuddha', status: 'standby', runtime: '0h 00min', generation: 0, cpuUsage: 15, memoryUsage: 4, temperature: 28, gpuUsage: 0, vramUsage: 0, powerDraw: 45, tflops: 0 },
];

export const useExperiment = () => {
  const [simulationState, setSimulationState] = useState<SimulationState | null>(null);
  const stateRef = useRef<SimulationState | null>(null);
  const frameIdRef = useRef<number>(0);
  const startTimeRef = useRef<number>(Date.now());
  const lastGenTimeRef = useRef<number>(0);
  const playbackIndexRef = useRef<number>(0);

  // Initialization helper
  const initializeState = useCallback((preserveSettings = false, mode: 'theory' | 'experimental' = 'theory') => {
    const initialStrategies = Object.values(StrategyType).reduce((acc, type) => {
      const pop = createInitialPopulation(POPULATION_SIZE);
      const adj = generateAdjacency(pop);
      const rawFitness = computeFitness(pop, adj); 
      const mod = computeModularity(adj);

      acc[type] = {
        type,
        population: pop,
        fitness: rawFitness,
        modularity: mod,
        adjacency: adj,
        fitnessHistory: Array(HISTORY_LENGTH).fill(0),
        variance: 0,
        varianceHistory: Array(HISTORY_LENGTH).fill(0)
      };
      return acc;
    }, {} as Record<StrategyType, StrategyData>);

    // If preserving settings, grab the current delay, otherwise default to 100
    const currentDelay = (preserveSettings && stateRef.current) 
        ? stateRef.current.simulationDelay 
        : 100;

    const initialState: SimulationState = {
      id: Math.random().toString(36).substring(7), // Unique Session ID
      generation: mode === 'experimental' ? 0 : 10,
      simulationDelay: currentDelay, 
      strategies: initialStrategies,
      cluster: INITIAL_NODES,
      metrics: {
        topoLead: 0,
        modularityScore: 0,
        thesisProgress: mode === 'experimental' ? 0 : 15
      },
      isRunning: true,
      telemetryMode: 'simulated',
      isLocalConnected: false,
      playbackMode: mode
    };

    playbackIndexRef.current = 0;
    stateRef.current = initialState;
    setSimulationState(initialState);
  }, []);

  // Initialize once
  useEffect(() => {
    initializeState(false, 'theory');
  }, [initializeState]);

  // Polling for Local Telemetry
  useEffect(() => {
    const pollInterval = setInterval(async () => {
      if (!stateRef.current || stateRef.current.telemetryMode !== 'local') return;

      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 800);

        const response = await fetch(`http://localhost:${TELEMETRY_PORT}/stats`, { 
            signal: controller.signal 
        });
        clearTimeout(timeoutId);

        if (response.ok) {
          const realData = await response.json();
          // Expecting realData to be an array of ClusterNodes or a single object to merge
          if (Array.isArray(realData)) {
             stateRef.current.cluster = realData;
             stateRef.current.isLocalConnected = true;
          }
        }
      } catch (e) {
        stateRef.current.isLocalConnected = false;
        // Keep existing data but mark disconnected
      }
    }, 1000);

    return () => clearInterval(pollInterval);
  }, []);

  const tick = useCallback(() => {
    if (!stateRef.current || !stateRef.current.isRunning) return;

    // Time throttling logic for variable speed
    const now = Date.now();
    const elapsed = now - lastGenTimeRef.current;

    if (elapsed < stateRef.current.simulationDelay) {
        frameIdRef.current = requestAnimationFrame(tick);
        return;
    }

    lastGenTimeRef.current = now;

    // --- PLAYBACK MODE (EXPERIMENTAL DATA) ---
    if (stateRef.current.playbackMode === 'experimental') {
        const idx = playbackIndexRef.current;

        // Loop playback
        if (idx >= EXPERIMENTAL_DATASET.length) {
            playbackIndexRef.current = 0;
            // Short pause at end loop could be handled here, but simplest is continuous loop
        }

        const dataPoint = EXPERIMENTAL_DATASET[playbackIndexRef.current];
        const prevStrategies = stateRef.current.strategies;
        const nextStrategies = {} as Record<StrategyType, StrategyData>;

        // Update strategies based on recorded data
        Object.values(StrategyType).forEach(type => {
            let val = 0;
            let std = 0;
            switch(type) {
                case StrategyType.Direct: 
                    val = dataPoint.direct; 
                    std = dataPoint.directStd;
                    break;
                case StrategyType.Flat: 
                    val = dataPoint.flat; 
                    std = dataPoint.flatStd;
                    break;
                case StrategyType.Hierarchical: 
                    val = dataPoint.hierarchical; 
                    std = dataPoint.hierStd;
                    break;
                case StrategyType.Topological: 
                    val = dataPoint.topological; 
                    std = dataPoint.topoStd;
                    break;
            }

            const prev = prevStrategies[type];
            const nextHistory = [...prev.fitnessHistory, val].slice(-HISTORY_LENGTH);
            const nextVarHistory = [...prev.varianceHistory, std].slice(-HISTORY_LENGTH);

            // For visuals, we need an adjacency matrix.
            // For Topological, we generate one that LOOKS like the data.
            // For others, we can keep static noise or generate random noise.
            let nextAdj = prev.adjacency;
            if (type === StrategyType.Topological) {
                nextAdj = generateSyntheticAdjacency(dataPoint.modularity);
            } else if (idx % 10 === 0) {
                 // Regenerate random noise occasionally for others to show "aliveness"
                 nextAdj = generateAdjacency(createInitialPopulation(POPULATION_SIZE));
            }

            nextStrategies[type] = {
                ...prev,
                fitness: val,
                modularity: type === StrategyType.Topological ? dataPoint.modularity : 0.1,
                fitnessHistory: nextHistory,
                variance: std,
                varianceHistory: nextVarHistory,
                adjacency: nextAdj
            };
        });

        // Update Global Metrics
        const topoLead = dataPoint.topological - Math.max(dataPoint.direct, dataPoint.flat, dataPoint.hierarchical);

        const nextState: SimulationState = {
            ...stateRef.current,
            generation: dataPoint.gen,
            strategies: nextStrategies,
            metrics: {
                topoLead,
                modularityScore: dataPoint.modularity,
                thesisProgress: (playbackIndexRef.current / EXPERIMENTAL_DATASET.length) * 100
            }
        };

        playbackIndexRef.current++;
        stateRef.current = nextState;
        setSimulationState(nextState);
        frameIdRef.current = requestAnimationFrame(tick);
        return;
    }


    // --- THEORY MODE (LIVE SIMULATION) ---
    const currentStrategies = stateRef.current.strategies;
    const nextStrategies = {} as Record<StrategyType, StrategyData>;
    let topoFitness = 0;
    let maxOtherFitness = -999;
    let topoModularity = 0;

    // Evolve strategies
    Object.values(StrategyType).forEach(type => {
      const prev = currentStrategies[type];
      const nextPop = evolvePopulation(prev.population, type);
      const nextAdj = generateAdjacency(nextPop);
      const adjustedFitness = computeFitness(nextPop, nextAdj); 
      const nextModularity = computeModularity(nextAdj);
      const nextHistory = [...prev.fitnessHistory, adjustedFitness].slice(-HISTORY_LENGTH);

      // Calculate Volatility/Variance based on history stability
      const volatility = computeHistoryVariance(nextHistory);
      const nextVarHistory = [...prev.varianceHistory, volatility].slice(-HISTORY_LENGTH);

      nextStrategies[type] = {
        type,
        population: nextPop,
        fitness: adjustedFitness,
        modularity: nextModularity,
        adjacency: nextAdj,
        fitnessHistory: nextHistory,
        variance: volatility,
        varianceHistory: nextVarHistory
      };

      if (type === StrategyType.Topological) {
        topoFitness = adjustedFitness;
        topoModularity = nextModularity;
      } else {
        maxOtherFitness = Math.max(maxOtherFitness, adjustedFitness);
      }
    });

    const topoLead = topoFitness - maxOtherFitness;
    const impulse = (topoLead * 20) + (topoModularity * 2); 
    const thesisProgress = Math.min(100, Math.max(0, 
      stateRef.current.metrics.thesisProgress * 0.99 + impulse
    ));

    // Update Cluster Telemetry
    let nextCluster = stateRef.current.cluster;

    if (stateRef.current.telemetryMode === 'simulated') {
        const time = (Date.now() - startTimeRef.current) / 1000;
        nextCluster = stateRef.current.cluster.map((node, i) => {
            const phase = i * (Math.PI / 2);
            const thermalCycle = Math.sin(time * 0.5 + phase) * 2; 
            const jitter = (Math.random() - 0.5) * 1.5;

            let newGen = node.generation;
            if (node.name === 'muladhara') {
                newGen += 1;
            } else if (Math.random() > 0.8) {
                newGen += 1; 
            }

            let status = node.status;
            if (newGen > 0 && status === 'syncing') status = 'active';
            const baseTemp = node.name === 'muladhara' ? 62 : 45;

            // Simulation logic for new metrics
            const isActive = status === 'active';
            const loadFactor = isActive ? 1.0 : 0.1;
            const targetTflops = isActive ? (node.name === 'muladhara' ? 125 : 80) : 0;
            const targetGpu = isActive ? (node.name === 'muladhara' ? 95 : 60) : 0;
            const targetPower = isActive ? (node.name === 'muladhara' ? 450 : 300) : 50;

            return {
                ...node,
                cpuUsage: Math.max(5, Math.min(100, Math.round(node.cpuUsage + (Math.random() - 0.5) * 10))),
                memoryUsage: Math.max(1, parseFloat((node.memoryUsage + (Math.random() - 0.5) * 0.1).toFixed(1))),
                temperature: Math.round(baseTemp + thermalCycle + jitter),
                generation: newGen,
                gpuUsage: Math.max(0, Math.min(100, Math.round(targetGpu + (Math.random() - 0.5) * 5))),
                vramUsage: parseFloat((node.vramUsage * 0.99 + (isActive ? 20 : 2) * 0.01).toFixed(1)),
                powerDraw: Math.round(node.powerDraw * 0.9 + targetPower * 0.1 + (Math.random() - 0.5) * 10),
                tflops: Math.round(node.tflops * 0.9 + targetTflops * 0.1)
            };
        });
    }

    const nextState: SimulationState = {
      id: stateRef.current.id,
      generation: stateRef.current.generation + 1,
      simulationDelay: stateRef.current.simulationDelay,
      strategies: nextStrategies,
      cluster: nextCluster,
      metrics: {
        topoLead,
        modularityScore: topoModularity,
        thesisProgress
      },
      isRunning: stateRef.current.isRunning,
      telemetryMode: stateRef.current.telemetryMode,
      isLocalConnected: stateRef.current.isLocalConnected,
      playbackMode: 'theory'
    };

    stateRef.current = nextState;
    setSimulationState(nextState);
    frameIdRef.current = requestAnimationFrame(tick);
  }, []);

  useEffect(() => {
    if (stateRef.current?.isRunning) {
        frameIdRef.current = requestAnimationFrame(tick);
    }
    return () => cancelAnimationFrame(frameIdRef.current);
  }, [tick, simulationState?.isRunning]);

  const togglePause = () => {
    if (stateRef.current) {
        stateRef.current.isRunning = !stateRef.current.isRunning;
        setSimulationState({...stateRef.current});
    }
  };

  const resetExperiment = () => {
      // Preserve current mode
      initializeState(true, stateRef.current?.playbackMode); 
  };

  const togglePlaybackMode = (mode: 'theory' | 'experimental') => {
      initializeState(true, mode);
  }

  const setTelemetryMode = (mode: 'simulated' | 'local') => {
      if (stateRef.current) {
          stateRef.current.telemetryMode = mode;
          setSimulationState({...stateRef.current});
      }
  };

  const setSimulationDelay = (delay: number) => {
    if (stateRef.current) {
        stateRef.current.simulationDelay = delay;
        setSimulationState({...stateRef.current});
    }
  };

  return { 
      state: simulationState, 
      togglePause, 
      resetExperiment, 
      setTelemetryMode, 
      setSimulationDelay,
      togglePlaybackMode // Exported for App.tsx
  };
};

