         {[0, 25, 50, 75, 100].map((tick) => (
             <div key={tick} className="h-full w-px bg-slate-400" />
         ))}
      </div>

      {/* Dynamic Progress Bar */}
      <div 
        className="h-full transition-all duration-300 ease-out flex items-center justify-end pr-2 relative z-10"
        style={{ 
          width: `${progress}%`,
          backgroundColor: color,
          boxShadow: `0 0 20px -5px ${color}`
        }}
